import type { User } from '../types';

export class ScopeViolationError extends Error {
  code = 'RBAC_SCOPE_VIOLATION' as const;

  constructor() {
    super('RBAC_SCOPE_VIOLATION');
    this.name = 'ScopeViolationError';
  }
}

export function assertSiteScope(actor: User, recordSiteId: number): void {
  if (actor.role !== 'SystemAdministrator' && actor.siteId !== recordSiteId) {
    throw new ScopeViolationError();
  }
}
```
**Summary:** Simple RBAC scope validation. Exports a custom error class and an `assertSiteScope` function that enforces site-level access control. SystemAdministrators can access any site; other roles are restricted to their assigned siteId.

