### 3. **src/hooks/useAuth.ts** (99 lines)
```typescript
import {
  createElement,
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  type PropsWithChildren
} from 'react';
import { authService } from '../services/authService';
import type { NavMode, User, UserRole } from '../types';

interface AuthContextValue {
  currentUser: User | null;
  navMode: NavMode;
  isRestoringSession: boolean;
  login: (username: string, password: string) => Promise<void>;
  logout: () => void;
  hasRole: (...roles: UserRole[]) => boolean;
  encryptionKey: CryptoKey | null;
}

const AuthContext = createContext<AuthContextValue | undefined>(undefined);

function deriveNavMode(user: User | null): NavMode {
  if (!user) {
    return 'kiosk';
  }

  return user.role === 'Attendant' || user.role === 'SiteManager' ? 'kiosk' : 'admin';
}

export function AuthProvider({ children }: PropsWithChildren) {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [encryptionKey, setEncryptionKey] = useState<CryptoKey | null>(null);
  const [isRestoringSession, setIsRestoringSession] = useState(true);

  useEffect(() => {
    const restore = async () => {
      try {
        const user = await authService.restoreSession();
        setCurrentUser(user);
      } finally {
        setIsRestoringSession(false);
      }
    };

    void restore();
  }, []);

  const login = useCallback(async (username: string, password: string) => {
    const { user, encryptionKey: key } = await authService.login(username, password);
    setCurrentUser(user);
    setEncryptionKey(key);
  }, []);

  const logout = useCallback(() => {
    authService.logout();
    setCurrentUser(null);
    setEncryptionKey(null);
  }, []);

  const hasRole = useCallback(
    (...roles: UserRole[]) => {
      if (!currentUser) {
        return false;
      }

      return roles.includes(currentUser.role);
    },
    [currentUser]
  );

  const value = useMemo<AuthContextValue>(
    () => ({
      currentUser,
      navMode: deriveNavMode(currentUser),
      isRestoringSession,
      login,
      logout,
      hasRole,
      encryptionKey
    }),
    [currentUser, encryptionKey, hasRole, isRestoringSession, login, logout]
  );

  return createElement(AuthContext.Provider, { value }, children);
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }

  return context;
}
```
**Summary:** React Context-based auth provider managing user state, session restoration, login/logout, role checking, and encryption key storage. Automatically restores sessions on mount. Distinguishes between 'kiosk' and 'admin' nav modes based on user role.

