61	function parseCsv(csv: string): { headers: string[]; rows: Record<string, string>[] } {
62	  const lines = csv
63	    .split(/\r?\n/)
64	    .map((line) => line.trim())
65	    .filter(Boolean);
66	  if (lines.length === 0) {
67	    return { headers: [], rows: [] };
68	  }
69	  const headers = lines[0].split(',').map((entry) => entry.trim());
70	  const rows = lines.slice(1).map((line) => {
71	    const cells = line.split(',');
72	    const row: Record<string, string> = {};
73	    headers.forEach((header, index) => {
74	      row[header] = (cells[index] ?? '').trim();
75	    });
76	    return row;
77	  });
78	
79	  return { headers, rows };
80	}
81	
82	function parseDate(value: string): number | null {
83	  const match = value.match(/^(\d{2})\/(\d{2})\/(\d{4})\s(\d{2}):(\d{2})$/);
84	  if (!match) {
85	    return null;
86	  }
87	  const [, mm, dd, yyyy, hh, min] = match;
88	  const date = new Date(Number(yyyy), Number(mm) - 1, Number(dd), Number(hh), Number(min));
89	  if (Number.isNaN(date.getTime())) {
90	    return null;
91	  }
92	  return date.getTime();
93	}
94	
95	async function sha256(text: string): Promise<string> {
96	  const buffer = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(text));
97	  return [...new Uint8Array(buffer)].map((b) => b.toString(16).padStart(2, '0')).join('');
98	}
99	
100	async function parseFile(file: File): Promise<{ headers: string[]; rows: Record<string, string>[]; raw: string }> {
101	  const readAsText =
102	    'text' in file
103	      ? async () => (await (file as unknown as { text: () => Promise<string> }).text())
104	      : async () =>
105	          await new Promise<string>((resolve, reject) => {
106	            const reader = new FileReader();
107	            reader.onload = () => resolve(String(reader.result ?? ''));
108	            reader.onerror = () => reject(reader.error);
109	            reader.readAsText(file);
110	          });
111	
112	  const readAsArrayBuffer =
113	    'arrayBuffer' in file
114	      ? async () =>
115	          await (file as unknown as { arrayBuffer: () => Promise<ArrayBuffer> }).arrayBuffer()
116	      : async () =>
117	          await new Promise<ArrayBuffer>((resolve, reject) => {
118	            const reader = new FileReader();
119	            reader.onload = () => resolve(reader.result as ArrayBuffer);
120	            reader.onerror = () => reject(reader.error);
121	            reader.readAsArrayBuffer(file);
122	          });
123	
124	  if (file.name.toLowerCase().endsWith('.xlsx')) {
125	    const bytes = await readAsArrayBuffer();
126	    const workbook = XLSX.read(bytes, { type: 'array' });
127	    const sheet = workbook.Sheets[workbook.SheetNames[0]];
128	    const matrix = XLSX.utils.sheet_to_json<(string | number)[]>(sheet, { header: 1 });
129	    const [headersRow = [], ...body] = matrix;
130	    const headers = headersRow.map((cell) => String(cell).trim());
131	    const rows = body.map((cells) => {
132	      const row: Record<string, string> = {};
133	      headers.forEach((header, index) => {
134	        row[header] = String(cells[index] ?? '').trim();
135	      });
136	      return row;
137	    });
138	    return { headers, rows, raw: JSON.stringify(matrix) };
139	  }
140	
141	  const text = await readAsText();
142	  const parsed = parseCsv(text);
143	  return { ...parsed, raw: text };
144	}
145	
146	function applyFieldMap(row: Record<string, string>, fieldMap: FieldMap): Record<string, string> {
147	  const mapped: Record<string, string> = {};
148	  Object.entries(fieldMap).forEach(([source, target]) => {
149	    if (target) {
150	      mapped[target] = row[source] ?? '';
151	    }
152	  });
153	  return mapped;
154	}
155	
156	async function validateRows(
157	  rows: Record<string, string>[],
158	  type: ImportType,
159	  actor: User
160	): Promise<{ importRows: ImportRow[]; invalidCount: number; validCount: number }> {
161	  const output: ImportRow[] = [];
162	  let invalidCount = 0;
163	  let validCount = 0;
164	
165	  for (let index = 0; index < rows.length; index += 1) {
166	    const row = rows[index];
167	    let errorCode: string | undefined;
168	
169	    for (const field of REQUIRED_FIELDS[type]) {
170	      if (!row[field]) {
171	        errorCode = 'IMPORT_REQUIRED_FIELD_MISSING';
172	      }
173	    }
174	
175	    if (!errorCode && type === 'reservations') {
176	      const start = parseDate(row.scheduledStart);
177	      const end = parseDate(row.scheduledEnd);
178	      if (!start || !end) {
179	        errorCode = 'IMPORT_DATE_FORMAT_INVALID';
180	      } else if (start >= end) {
181	        errorCode = 'IMPORT_DATE_RANGE_INVALID';
182	      } else {
183	        const bay = await db.bays
184	          .where('siteId')
185	          .equals(actor.siteId as number)
186	          .filter((b) => b.stationId === row.stationId && b.connectorId === row.connectorId)
187	          .first();
188	        if (!bay) {
189	          errorCode = 'IMPORT_BAY_NOT_FOUND';
190	        }
191	      }
192	    }
193	
194	    if (!errorCode && type === 'orders') {
195	      const duration = Number(row.durationMinutes);
196	      const rate = Number(row.ratePerMinute);
197	      const adjustment = Number(row.adjustmentAmount);
198	      if (!(duration > 0)) {
199	        errorCode = 'IMPORT_DURATION_INVALID';
200	      } else if (!(rate > 0) || Number(rate.toFixed(2)) !== rate) {
201	        errorCode = 'IMPORT_RATE_INVALID';
202	      } else if (Number.isNaN(adjustment)) {
203	        errorCode = 'IMPORT_ADJUSTMENT_INVALID';
204	      }
205	    }
206	
207	    output.push({
208	      batchId: 0,
209	      rowIndex: index + 1,
210	      status: errorCode ? 'Invalid' : 'Valid',
211	      rawData: JSON.stringify(rows[index]),
212	      cleanedData: JSON.stringify(row),
213	      errorCode
214	    });
215	
216	    if (errorCode) {
217	      invalidCount += 1;
218	    } else {
219	      validCount += 1;
220	    }
221	  }
222	
223	  return { importRows: output, invalidCount, validCount };
224	}
