226	function autoMapFields(headers: string[], type: ImportType): FieldMap {
227	  const required = REQUIRED_FIELDS[type];
228	  const lowerMap = new Map(required.map((field) => [field.toLowerCase(), field]));
229	  const map: FieldMap = {};
230	  headers.forEach((header) => {
231	    const target = lowerMap.get(header.toLowerCase());
232	    map[header] = target ?? '';
233	  });
234	  return map;
235	}
236	
237	function generateCsv(rows: string[][]): string {
238	  return rows.map((line) => line.join(',')).join('\n');
239	}
