241	function downloadTemplate(type: ImportType): void {
242	  const def = TEMPLATE_ROWS[type];
243	  const csv = generateCsv([def.headers, def.sample]);
244	  const blob = new Blob([csv], { type: 'text/csv' });
245	  const url = URL.createObjectURL(blob);
246	  const a = document.createElement('a');
247	  a.href = url;
248	  a.download = `${type}_template.csv`;
249	  a.click();
250	  URL.revokeObjectURL(url);
251	}
252	
253	async function validateFile(
254	  file: File,
255	  type: ImportType,
256	  fieldMap: FieldMap,
257	  actor: User
258	): Promise<{ totalRows: number; validRows: number; invalidRows: number; rows: ImportRow[]; headers: string[] }> {
259	  const parsed = await parseFile(file);
260	  const mappedRows = parsed.rows.map((row) => applyFieldMap(row, fieldMap));
261	  const validated = await validateRows(mappedRows, type, actor);
262	  return {
263	    totalRows: mappedRows.length,
264	    validRows: validated.validCount,
265	    invalidRows: validated.invalidCount,
266	    rows: validated.importRows,
267	    headers: parsed.headers
268	  };
269	}
