271	async function startImport(
272	  file: File,
273	  type: ImportType,
274	  fieldMap: FieldMap,
275	  actor: User
276	): Promise<ImportBatch> {
277	  const parsed = await parseFile(file);
278	  const dedupeHash = await sha256(parsed.raw);
279	
280	  const existingBatch = await db.importBatches
281	    .where('siteId')
282	    .equals(actor.siteId as number)
283	    .filter((b) => b.dedupeHash === dedupeHash)
284	    .first();
285	  if (existingBatch) {
286	    throw new Error('IMPORT_DUPLICATE_FILE');
287	  }
288	
289	  const batchId = await db.importBatches.add({
290	    siteId: actor.siteId as number,
291	    type,
292	    status: 'Validating',
293	    createdAt: Date.now(),
294	    dedupeHash
295	  });
296	
297	  const mappedRows = parsed.rows.map((row) => applyFieldMap(row, fieldMap));
298	  const validation = await validateRows(mappedRows, type, actor);
299	  const validationRows = validation.importRows.map((row) => ({ ...row, batchId }));
300	  await db.importRows.bulkAdd(validationRows);
301	
302	  if (validation.invalidCount > 0) {
303	    await db.importBatches.update(batchId, {
304	      status: 'Failed',
305	      totalRows: mappedRows.length,
306	      validRows: validation.validCount,
307	      invalidRows: validation.invalidCount,
308	      duplicateRows: 0,
309	      errorSummary: `${validation.invalidCount} invalid rows`
310	    });
311	    await notificationService.send(actor.id as number, 'IMPORT_FAILED', {
312	      batchId: String(batchId),
313	      reason: `${validation.invalidCount} validation errors`
314	    });
315	    return (await db.importBatches.get(batchId)) as ImportBatch;
316	  }
317	
318	  let duplicateRows = 0;
319	  await db.transaction(
320	    'rw',
321	    db.reservations,
322	    db.orders,
323	    db.sessions_charging,
324	    db.bays,
325	    db.importRows,
326	    async () => {
327	      for (let index = 0; index < mappedRows.length; index += 1) {
328	        const row = mappedRows[index];
329	        let isDuplicate = false;
330	
331	        if (type === 'reservations') {
332	          const start = parseDate(row.scheduledStart) as number;
333	          const bay = await db.bays
334	            .where('siteId')
335	            .equals(actor.siteId as number)
336	            .filter((b) => b.stationId === row.stationId && b.connectorId === row.connectorId)
337	            .first();
338	
339	          const dup = await db.reservations
340	            .where('siteId')
341	            .equals(actor.siteId as number)
342	            .filter((r) => r.bayId === bay?.id && r.scheduledStart === start)
343	            .first();
344	          if (dup) {
345	            isDuplicate = true;
346	          } else {
347	            await db.reservations.add({
348	              operationId: crypto.randomUUID(),
349	              bayId: bay?.id as number,
350	              siteId: actor.siteId as number,
351	              userId: actor.id as number,
352	              customerName: row.customerName,
353	              customerPlate: row.customerPlate,
354	              scheduledStart: start,
355	              scheduledEnd: parseDate(row.scheduledEnd) as number,
356	              status: 'Scheduled',
357	              noShowDeadline: start + 10 * 60_000,
358	              version: 1
359	            });
360	          }
361	        }
362	
363	        if (type === 'orders') {
364	          const dup = await db.orders
365	            .where('siteId')
366	            .equals(actor.siteId as number)
367	            .filter((o) => o.orderNumber === row.orderNumber)
368	            .first();
369	          if (dup) {
370	            isDuplicate = true;
371	          } else {
372	            const duration = Number(row.durationMinutes);
373	            const rate = Number(row.ratePerMinute);
374	            const adjustment = Number(row.adjustmentAmount);
375	            const subtotal = Number((duration * rate).toFixed(2));
376	            await db.orders.add({
377	              operationId: crypto.randomUUID(),
378	              sessionId: Number(row.sessionId),
379	              siteId: actor.siteId as number,
380	              orderNumber: row.orderNumber,
381	              status: 'Draft',
382	              billingType: 'Standard',
383	              durationMinutes: duration,
384	              ratePerMinute: rate,
385	              subtotal,
386	              adjustmentAmount: adjustment,
387	              adjustmentReason: row.adjustmentReason,
388	              totalAmount: Number((subtotal + adjustment).toFixed(2)),
389	              invoiceNotes: row.invoiceNotes,
390	              reconciliationStatus: 'Unreconciled',
391	              version: 1
392	            });
393	          }
394	        }
395	
396	        if (type === 'sessions') {
397	          const startedAt = parseDate(row.startedAt);
398	          const dup = await db.sessions_charging
399	            .where('reservationId')
400	            .equals(Number(row.reservationId))
401	            .filter((s) => s.startedAt === startedAt)
402	            .first();
403	          if (dup) {
404	            isDuplicate = true;
405	          } else {
406	            const reservation = await db.reservations.get(Number(row.reservationId));
407	            if (reservation) {
408	              await db.sessions_charging.add({
409	                reservationId: reservation.id as number,
410	                bayId: reservation.bayId,
411	                siteId: reservation.siteId,
412	                startedAt: startedAt as number,
413	                status: 'Active',
414	                heartbeatAt: startedAt as number,
415	                tempLeaveCount: 0,
416	                version: 1
417	              });
418	            }
419	          }
420	        }
421	
422	        if (isDuplicate) {
423	          duplicateRows += 1;
424	          const row = await db.importRows
425	            .where('batchId')
426	            .equals(batchId)
427	            .filter((item) => item.rowIndex === index + 1)
428	            .first();
429	          if (row?.id) {
430	            await db.importRows.update(row.id, { status: 'Duplicate' });
431	          }
432	        } else {
433	          const row = await db.importRows
434	            .where('batchId')
435	            .equals(batchId)
436	            .filter((item) => item.rowIndex === index + 1)
437	            .first();
438	          if (row?.id) {
439	            await db.importRows.update(row.id, { status: 'Imported' });
440	          }
441	        }
442	      }
443	    }
444	  );
445	
446	  await db.importBatches.update(batchId, {
447	    status: 'Complete',
448	    totalRows: mappedRows.length,
449	    validRows: validation.validCount,
450	    invalidRows: validation.invalidCount,
451	    duplicateRows
452	  });
453	
454	  await notificationService.send(actor.id as number, 'IMPORT_COMPLETE', {
455	    rowCount: String(mappedRows.length - duplicateRows)
456	  });
457	  await auditService.log(actor, 'IMPORT_COMPLETED', 'ImportBatch', batchId, {
458	    type,
459	    totalRows: mappedRows.length,
460	    duplicateRows
461	  });
462	
463	  return (await db.importBatches.get(batchId)) as ImportBatch;
464	}
