26	async function generateOrder(sessionId: number, actor: User, encryptionKey?: CryptoKey): Promise<Order> {
27	  const existing = await db.orders.where('sessionId').equals(sessionId).filter((o) => o.status !== 'Voided').first();
28	  if (existing) {
29	    return existing;
30	  }
31	
32	  const session = await db.sessions_charging.get(sessionId);
33	  if (!session || session.status !== 'Completed' || !session.endedAt) {
34	    throw new Error('ORDER_SESSION_NOT_COMPLETED');
35	  }
36	  assertSiteScope(actor, session.siteId);
37	
38	  const config = siteConfigService.getSiteConfig(session.siteId);
39	  const site = await db.sites.get(session.siteId);
40	  const minutes = Math.max(1, Math.ceil((session.endedAt - session.startedAt) / 60_000));
41	  const subtotal = Number((minutes * config.ratePerMinute).toFixed(2));
42	  const total = subtotal;
43	  const dayKey = dateKey(session.endedAt);
44	  const todayOrders = await db.orders
45	    .where('siteId')
46	    .equals(session.siteId)
47	    .filter((order) => order.orderNumber.includes(dayKey))
48	    .count();
49	  const seq = String(todayOrders + 1).padStart(4, '0');
50	  const orderNumber = `CB-${site?.siteCode ?? 'SITE'}-${dayKey}-${seq}`;
51	  const operationId = `order-${sessionId}`;
52	
53	  const idempotent = (await db.orders.toArray()).find((order) => order.operationId === operationId);
54	  if (idempotent) {
55	    return idempotent;
56	  }
57	
58	  const encryptedNotes = encryptionKey
59	    ? await cryptoService.encryptField('', encryptionKey)
60	    : btoa('');
61	
62	  const orderId = await db.orders.add({
63	    operationId,
64	    sessionId,
65	    siteId: session.siteId,
66	    createdAt: Date.now(),
67	    orderNumber,
68	    status: 'Draft',
69	    billingType: 'Standard',
70	    durationMinutes: minutes,
71	    ratePerMinute: config.ratePerMinute,
72	    subtotal,
73	    adjustmentAmount: 0,
74	    totalAmount: total,
75	    invoiceNotes: encryptedNotes,
76	    reconciliationStatus: 'Unreconciled',
77	    version: 1
78	  });
79	
80	  await auditService.log(actor, 'ORDER_GENERATED', 'Order', orderId, { sessionId, orderNumber });
81	  return (await db.orders.get(orderId)) as Order;
82	}
