63	function prefsKey(userId: number) {
64	  return `cb_notif_prefs_${userId}`;
65	}
66	
67	function defaultPrefs(userId: number): NotificationPrefs {
68	  const enabled = Object.keys(TEMPLATES).reduce((acc, key) => {
69	    acc[key as NotificationTemplate] = true;
70	    return acc;
71	  }, {} as Record<NotificationTemplate, boolean>);
72	
73	  return {
74	    userId,
75	    enabled,
76	    showDesktopBanner: true
77	  };
78	}
79	
80	function getPrefs(userId: number): NotificationPrefs {
81	  const raw = localStorage.getItem(prefsKey(userId));
82	  if (!raw) {
83	    return defaultPrefs(userId);
84	  }
85	
86	  try {
87	    const parsed = JSON.parse(raw) as NotificationPrefs;
88	    return {
89	      ...defaultPrefs(userId),
90	      ...parsed,
91	      enabled: {
92	        ...defaultPrefs(userId).enabled,
93	        ...parsed.enabled
94	      }
95	    };
96	  } catch {
97	    return defaultPrefs(userId);
98	  }
99	}
