115	async function deliver(notificationId: number): Promise<void> {
116	  const notification = await db.notifications.get(notificationId);
117	  if (!notification || notification.status === 'Archived') {
118	    return;
119	  }
120	
121	  try {
122	    const template = TEMPLATES[notification.templateKey];
123	    const renderedSubject = renderTemplate(template.subject, notification.templateData);
124	    const renderedBody = renderTemplate(template.body, notification.templateData);
125	    await db.notifications.update(notificationId, {
126	      status: 'Delivered',
127	      renderedSubject,
128	      renderedBody,
129	      lastAttemptAt: Date.now(),
130	      failureReason: undefined
131	    });
132	
133	    const prefs = getPrefs(notification.recipientId);
134	    if (prefs.showDesktopBanner && bannerListener) {
135	      bannerListener(renderedSubject, notification.recipientId);
136	    }
137	  } catch (error) {
138	    const retries = notification.retries + 1;
139	    const message = error instanceof Error ? error.message : 'Delivery error';
140	    await db.notifications.update(notificationId, {
141	      retries,
142	      failureReason: message,
143	      lastAttemptAt: Date.now(),
144	      status: retries >= 3 ? 'Failed' : 'Pending'
145	    });
146	
147	    if (retries < 3) {
148	      window.setTimeout(() => {
149	        void deliver(notificationId);
150	      }, 5_000);
151	    }
152	  }
153	}
