155	async function send(
156	  recipientId: number,
157	  templateKey: NotificationTemplate,
158	  templateData: Record<string, string>
159	): Promise<Notification | null> {
160	  const prefs = getPrefs(recipientId);
161	  if (prefs.enabled[templateKey] === false) {
162	    return null;
163	  }
164	
165	  const notification: Notification = {
166	    recipientId,
167	    templateKey,
168	    templateData,
169	    renderedSubject: '',
170	    renderedBody: '',
171	    status: 'Pending',
172	    isRead: false,
173	    retries: 0,
174	    createdAt: Date.now()
175	  };
176	
177	  const id = await db.notifications.add(notification);
178	  await deliver(id);
179	  return (await db.notifications.get(id)) as Notification;
180	}
