235	async function runDueAndOverdueSchedulers(actor: User): Promise<void> {
236	  const now = Date.now();
237	  const reservations = await db.reservations
238	    .where('status')
239	    .equals('Scheduled')
240	    .filter((r) => (actor.role === 'SystemAdministrator' ? true : r.siteId === actor.siteId))
241	    .toArray();
242	
243	  for (const reservation of reservations) {
244	    const dueMin = reservation.scheduledStart - now;
245	    if (dueMin >= 14 * 60_000 && dueMin <= 16 * 60_000 && !sentDueReminder.has(reservation.id as number)) {
