42	async function createReservation(
43	  data: CreateReservationInput,
44	  actor: User,
45	  encryptionKey: CryptoKey
46	): Promise<Reservation> {
47	  assertSiteScope(actor, data.siteId);
48	  const now = Date.now();
49	  if (data.scheduledStart >= data.scheduledEnd || data.scheduledStart <= now) {
50	    throw new Error('RES_INVALID_TIME_WINDOW');
51	  }
52	
53	  const existing = await db.reservations.where('operationId').equals(data.operationId).first();
54	  if (existing) {
55	    return existing;
56	  }
57	
58	  const activeReservations = await db.reservations
59	    .where('bayId')
60	    .equals(data.bayId)
61	    .filter((item) => ['Scheduled', 'CheckedIn', 'Active'].includes(item.status))
62	    .toArray();
63	
64	  const hasConflict = activeReservations.some((item) =>
65	    overlaps(data.scheduledStart, data.scheduledEnd, item.scheduledStart, item.scheduledEnd)
66	  );
67	  if (hasConflict) {
68	    throw new BayConflictError();
69	  }
70	
71	  const site = await db.sites.get(data.siteId);
72	  const qrPayload = qrService.encodePayload({
73	    reservationId: 0,
74	    operationId: data.operationId,
75	    siteCode: site?.siteCode ?? 'UNKNOWN'
76	  });
77	  const config = siteConfigService.getSiteConfig(data.siteId);
78	
79	  const reservation: Reservation = {
80	    operationId: data.operationId,
81	    bayId: data.bayId,
82	    siteId: data.siteId,
83	    userId: data.userId,
84	    customerName: await cryptoService.encryptField(data.customerName, encryptionKey),
85	    customerPlate: await cryptoService.encryptField(data.customerPlate, encryptionKey),
86	    scheduledStart: data.scheduledStart,
87	    scheduledEnd: data.scheduledEnd,
88	    status: 'Scheduled',
89	    qrCode: qrPayload,
90	    noShowDeadline: data.scheduledStart + config.noShowGraceMinutes * 60_000,
91	    version: 1
92	  };
93	
94	  const reservationId = await db.reservations.add(reservation);
95	  await db.bays.update(data.bayId, { status: 'Reserved' });
96	  await auditService.log(actor, 'RESERVATION_CREATED', 'Reservation', reservationId, {
97	    bayId: data.bayId,
98	    scheduledStart: data.scheduledStart
99	  });
100	
101	  const created = await db.reservations.get(reservationId);
102	  return created as Reservation;
103	}
