105	async function confirmArrival(
106	  reservationId: number,
107	  method: 'manual' | 'qr',
108	  actor: User,
109	  qrPayload?: string
110	): Promise<ChargingSession> {
111	  const reservation = await db.reservations.get(reservationId);
112	  if (!reservation || reservation.status !== 'Scheduled') {
113	    throw new Error('RES_CONFIRM_INVALID_STATE');
114	  }
115	  assertSiteScope(actor, reservation.siteId);
116	
117	  if (method === 'qr') {
118	    if (!qrPayload) {
119	      throw new Error('RES_QR_MISSING');
120	    }
121	    const parsed = qrService.parsePayload(qrPayload);
122	    if (parsed.operationId !== reservation.operationId) {
123	      throw new Error('RES_QR_MISMATCH');
124	    }
125	  }
126	
127	  const now = Date.now();
128	  await db.reservations.update(reservationId, {
129	    status: 'CheckedIn',
130	    confirmedArrivalAt: now,
131	    confirmedBy: actor.id,
132	    version: reservation.version + 1
133	  });
134	  await db.bays.update(reservation.bayId, { status: 'Occupied' });
135	
136	  const session: ChargingSession = {
137	    reservationId,
138	    bayId: reservation.bayId,
139	    siteId: reservation.siteId,
140	    startedAt: now,
141	    status: 'Active',
142	    heartbeatAt: now,
143	    tempLeaveCount: 0,
144	    version: 1
145	  };
146	  const sessionId = await db.sessions_charging.add(session);
147	
148	  await db.reservations.update(reservationId, { status: 'Active' });
149	  await auditService.log(actor, 'ARRIVAL_CONFIRMED', 'Reservation', reservationId, {
150	    method,
151	    sessionId
152	  });
153	
154	  const created = await db.sessions_charging.get(sessionId);
155	  return created as ChargingSession;
156	}
