158	async function autoProcessNoShows(actor?: User): Promise<void> {
159	  const now = Date.now();
160	  const due = await db.reservations
161	    .where('status')
162	    .equals('Scheduled')
163	    .filter((item) => item.noShowDeadline <= now)
164	    .toArray();
165	
166	  for (const reservation of due) {
167	    await db.reservations.update(reservation.id as number, {
168	      status: 'NoShow',
169	      version: reservation.version + 1
170	    });
171	    await db.bays.update(reservation.bayId, { status: 'Available' });
172	
173	    if (actor) {
174	      await auditService.log(actor, 'RESERVATION_NO_SHOW', 'Reservation', reservation.id as number);
175	    }
176	    await notificationService.sendTemplateToSiteStaff(
177	      reservation.siteId,
178	      'NO_SHOW_CANCELLED',
179	      actor,
180	      {
181	        reservationId: String(reservation.id ?? ''),
182	        time: new Date(now).toLocaleTimeString()
183	      }
184	    );
185	  }
186	}
