188	async function flagAnomaly(sessionId: number, reason: string, actor: User): Promise<void> {
189	  const session = await db.sessions_charging.get(sessionId);
190	  if (!session) {
191	    throw new Error('SESSION_NOT_FOUND');
192	  }
193	  assertSiteScope(actor, session.siteId);
194	
195	  await db.sessions_charging.update(sessionId, {
196	    status: 'Anomaly',
197	    anomalyReason: reason,
198	    version: session.version + 1
199	  });
200	  await db.bays.update(session.bayId, { status: 'Anomaly' });
201	  await notificationService.sendTemplateToSiteStaff(session.siteId, 'OCCUPANCY_ANOMALY', actor, {
202	    bayLabel: String(session.bayId),
203	    reason
204	  });
205	  await auditService.log(actor, 'SESSION_ANOMALY_FLAGGED', 'ChargingSession', sessionId, { reason });
206	}
