208	async function startTempLeave(sessionId: number, actor: User): Promise<void> {
209	  const session = await db.sessions_charging.get(sessionId);
210	  if (!session || session.status !== 'Active') {
211	    throw new Error('SESSION_INVALID_STATE');
212	  }
213	  assertSiteScope(actor, session.siteId);
214	
215	  const config = siteConfigService.getSiteConfig(session.siteId);
216	  if (session.tempLeaveCount >= config.tempLeaveMaxCount) {
217	    throw new TempLeaveLimitError();
218	  }
219	
220	  await db.sessions_charging.update(sessionId, {
221	    status: 'TempLeave',
222	    tempLeaveStartedAt: Date.now(),
223	    version: session.version + 1
224	  });
225	  await auditService.log(actor, 'TEMP_LEAVE_STARTED', 'ChargingSession', sessionId);
226	}
227	
228	async function endTempLeave(sessionId: number, actor: User): Promise<void> {
229	  const session = await db.sessions_charging.get(sessionId);
230	  if (!session || session.status !== 'TempLeave') {
231	    throw new Error('SESSION_INVALID_STATE');
232	  }
233	  assertSiteScope(actor, session.siteId);
234	
235	  const now = Date.now();
236	  const config = siteConfigService.getSiteConfig(session.siteId);
237	  const duration = now - (session.tempLeaveStartedAt ?? now);
238	
239	  if (duration > config.tempLeaveMaxMinutes * 60_000) {
240	    await flagAnomaly(sessionId, 'Temp leave duration exceeded', actor);
241	    return;
242	  }
243	
244	  await db.sessions_charging.update(sessionId, {
245	    status: 'Active',
246	    tempLeaveStartedAt: undefined,
247	    tempLeaveCount: session.tempLeaveCount + 1,
248	    heartbeatAt: now,
249	    version: session.version + 1
250	  });
251	  await auditService.log(actor, 'TEMP_LEAVE_ENDED', 'ChargingSession', sessionId);
252	}
253	
254	async function getReservationDetail(
255	  reservationId: number,
256	  actor: User,
257	  encryptionKey: CryptoKey
258	): Promise<Reservation | null> {
259	  const reservation = await db.reservations.get(reservationId);
260	  if (!reservation) {
261	    return null;
262	  }
263	  assertSiteScope(actor, reservation.siteId);
264	
265	  return {
266	    ...reservation,
267	    customerName: await cryptoService.decryptField(reservation.customerName, encryptionKey),
268	    customerPlate: await cryptoService.decryptField(reservation.customerPlate, encryptionKey)
269	  };
270	}
271	
272	async function bulkCancelReservations(reservationIds: number[], actor: User): Promise<void> {
273	  const userId = actor.id as number;
274	  rateLimiter.check(userId, 'bulk_reservation_cancel', 100, 60_000, reservationIds.length);
275	  rateLimiter.record(userId, 'bulk_reservation_cancel', reservationIds.length);
276	
277	  for (const reservationId of reservationIds) {
278	    const reservation = await db.reservations.get(reservationId);
279	    if (!reservation) {
280	      continue;
281	    }
282	    assertSiteScope(actor, reservation.siteId);
283	    await db.reservations.update(reservationId, { status: 'Cancelled', version: reservation.version + 1 });
284	    await db.bays.update(reservation.bayId, { status: 'Available' });
285	    await auditService.log(actor, 'RESERVATION_CANCELLED', 'Reservation', reservationId);
286	  }
287	}
