1	import { db } from '../db/db';
2	import type { User } from '../types';
3	import { auditService } from './auditService';
4	import { cryptoService } from './cryptoService';
5	
6	interface DateRange {
7	  from: number;
8	  to: number;
9	}
10	
11	interface ExportPackage {
12	  version: 1;
13	  siteId: number;
14	  exportedAt: number;
15	  exportedBy: string;
16	  dateRange: DateRange;
17	  signature: string;
18	  salt: string;
19	  iv: string;
20	  ciphertext: string;
21	}
22	
23	function bytesToHex(bytes: Uint8Array): string {
24	  return [...bytes].map((b) => b.toString(16).padStart(2, '0')).join('');
25	}
26	
27	function hexToBytes(hex: string): Uint8Array {
28	  const out = new Uint8Array(hex.length / 2);
29	  for (let index = 0; index < out.length; index += 1) {
30	    out[index] = Number.parseInt(hex.slice(index * 2, index * 2 + 2), 16);
31	  }
32	  return out;
33	}
34	
35	function bytesToBase64(bytes: Uint8Array): string {
36	  let binary = '';
37	  for (const byte of bytes) binary += String.fromCharCode(byte);
38	  return btoa(binary);
39	}
40	
41	function base64ToBytes(base64: string): Uint8Array {
42	  const binary = atob(base64);
43	  const out = new Uint8Array(binary.length);
44	  for (let i = 0; i < binary.length; i += 1) out[i] = binary.charCodeAt(i);
45	  return out;
46	}
47	
48	async function sha256Hex(value: string): Promise<string> {
49	  const digest = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(value));
50	  return bytesToHex(new Uint8Array(digest));
51	}
52	
53	async function exportPackage(
54	  siteId: number,
55	  dateRange: DateRange,
56	  password: string,
57	  actor: User
58	): Promise<Blob> {
59	  const [reservations, sessions, orders, reservationsCold, sessionsCold, ordersCold] = await Promise.all([
60	    db.reservations
61	      .where('siteId')
62	      .equals(siteId)
63	      .filter((r) => r.scheduledStart >= dateRange.from && r.scheduledStart <= dateRange.to)
64	      .toArray(),
65	    db.sessions_charging
66	      .where('siteId')
67	      .equals(siteId)
68	      .filter((s) => s.startedAt >= dateRange.from && s.startedAt <= dateRange.to)
69	      .toArray(),
70	    db.orders.where('siteId').equals(siteId).toArray(),
71	    db.reservations_cold.where('siteId').equals(siteId).toArray(),
72	    db.sessions_cold.where('siteId').equals(siteId).toArray(),
73	    db.orders_cold.where('siteId').equals(siteId).toArray()
74	  ]);
75	
76	  const payload = JSON.stringify({
77	    reservations,
78	    sessions,
79	    orders,
80	    reservationsCold,
81	    sessionsCold,
82	    ordersCold
83	  });
84	  const signature = await sha256Hex(payload + password);
85	  const salt = bytesToHex(crypto.getRandomValues(new Uint8Array(16)));
86	  const key = await cryptoService.deriveEncryptionKey(password, salt);
87	  const iv = crypto.getRandomValues(new Uint8Array(12));
88	  const cipher = await crypto.subtle.encrypt(
89	    { name: 'AES-GCM', iv },
90	    key,
91	    new TextEncoder().encode(payload)
92	  );
93	
94	  const pkg: ExportPackage = {
95	    version: 1,
96	    siteId,
97	    exportedAt: Date.now(),
98	    exportedBy: actor.username,
99	    dateRange,
100	    signature,
101	    salt,
102	    iv: bytesToHex(iv),
103	    ciphertext: bytesToBase64(new Uint8Array(cipher))
104	  };
105	
106	  const json = JSON.stringify(pkg, null, 2);
107	  const blob = new Blob([json], { type: 'application/json' });
108	  const url = URL.createObjectURL(blob);
109	  const site = await db.sites.get(siteId);
110	  const a = document.createElement('a');
111	  a.href = url;
112	  a.download = `cb-export-${site?.siteCode ?? siteId}-${new Date().toISOString().slice(0, 10)}.json`;
113	  a.click();
114	  URL.revokeObjectURL(url);
115	
116	  await auditService.log(actor, 'EXPORT_PACKAGE_CREATED', 'Site', siteId);
117	  return blob;
118	}
119	
120	async function importPackage(file: File, password: string, actor: User): Promise<{ inserted: number; skipped: number }> {
121	  const text =
122	    'text' in file
123	      ? await (file as unknown as { text: () => Promise<string> }).text()
124	      : await new Promise<string>((resolve, reject) => {
125	          const reader = new FileReader();
126	          reader.onload = () => resolve(String(reader.result ?? ''));
127	          reader.onerror = () => reject(reader.error);
128	          reader.readAsText(file);
129	        });
130	
131	  const pkg = JSON.parse(text) as ExportPackage;
132	  if (pkg.version !== 1) {
133	    throw new Error('EXPORT_SIGNATURE_MISMATCH');
134	  }
135	
136	  try {
137	    const key = await cryptoService.deriveEncryptionKey(password, pkg.salt);
138	    const iv = hexToBytes(pkg.iv);
139	    const plain = await crypto.subtle.decrypt(
140	      { name: 'AES-GCM', iv: iv as unknown as BufferSource },
141	      key,
142	      base64ToBytes(pkg.ciphertext) as unknown as BufferSource
143	    );
144	    const payloadText = new TextDecoder().decode(plain);
145	    const signature = await sha256Hex(payloadText + password);
146	    if (signature !== pkg.signature) {
147	      throw new Error('EXPORT_SIGNATURE_MISMATCH');
148	    }
149	
150	    const payload = JSON.parse(payloadText) as {
151	      reservations: Array<{ id?: number }>;
152	      sessions: Array<{ id?: number }>;
153	      orders: Array<{ id?: number }>;
154	      reservationsCold: Array<{ id?: number }>;
155	      sessionsCold: Array<{ id?: number }>;
156	      ordersCold: Array<{ id?: number }>;
157	    };
158	
159	    let inserted = 0;
160	    let skipped = 0;
161	    for (const row of payload.reservations) {
162	      if (row.id && (await db.reservations.get(row.id))) {
163	        skipped += 1;
164	      } else {
165	        await db.reservations.add(row as never);
166	        inserted += 1;
167	      }
168	    }
169	    for (const row of payload.sessions) {
170	      if (row.id && (await db.sessions_charging.get(row.id))) {
171	        skipped += 1;
172	      } else {
173	        await db.sessions_charging.add(row as never);
174	        inserted += 1;
175	      }
176	    }
177	    for (const row of payload.orders) {
178	      if (row.id && (await db.orders.get(row.id))) {
179	        skipped += 1;
180	      } else {
181	        await db.orders.add(row as never);
182	        inserted += 1;
183	      }
184	    }
185	    for (const row of payload.reservationsCold) {
186	      if (row.id && (await db.reservations_cold.get(row.id))) {
187	        skipped += 1;
188	      } else {
189	        await db.reservations_cold.add(row as never);
190	        inserted += 1;
191	      }
192	    }
193	    for (const row of payload.sessionsCold) {
194	      if (row.id && (await db.sessions_cold.get(row.id))) {
195	        skipped += 1;
196	      } else {
197	        await db.sessions_cold.add(row as never);
198	        inserted += 1;
199	      }
200	    }
201	    for (const row of payload.ordersCold) {
202	      if (row.id && (await db.orders_cold.get(row.id))) {
203	        skipped += 1;
204	      } else {
205	        await db.orders_cold.add(row as never);
206	        inserted += 1;
207	      }
208	    }
209	
210	    await auditService.log(actor, 'IMPORT_PACKAGE_APPLIED', 'Site', pkg.siteId, { inserted, skipped });
211	    return { inserted, skipped };
212	  } catch {
213	    throw new Error('EXPORT_SIGNATURE_MISMATCH');
214	  }
215	}
