13	async function completeSession(sessionId: number, actor: User): Promise<void> {
14	  const session = await db.sessions_charging.get(sessionId);
15	  if (!session || session.status !== 'Active') {
16	    throw new Error('SESSION_INVALID_STATE');
17	  }
18	  assertSiteScope(actor, session.siteId);
19	
20	  const now = Date.now();
21	  await db.sessions_charging.update(sessionId, {
22	    status: 'Completed',
23	    endedAt: now,
24	    version: session.version + 1
25	  });
26	  await db.bays.update(session.bayId, { status: 'Available' });
27	  await db.reservations.update(session.reservationId, { status: 'Completed' });
28	  await orderService.generateOrder(sessionId, actor);
29	  await auditService.log(actor, 'SESSION_COMPLETED', 'ChargingSession', sessionId);
30	}
31	
32	async function resolveAnomaly(
33	  sessionId: number,
34	  resolution: 'complete' | 'cancel',
35	  reason: string,
36	  actor: User
37	): Promise<void> {
38	  assertManagerOrAdmin(actor);
39	  if (reason.trim().length < 10) {
40	    throw new Error('ANOMALY_REASON_TOO_SHORT');
41	  }
42	
43	  const session = await db.sessions_charging.get(sessionId);
44	  if (!session || session.status !== 'Anomaly') {
45	    throw new Error('SESSION_INVALID_STATE');
46	  }
47	  assertSiteScope(actor, session.siteId);
48	
49	  if (resolution === 'complete') {
50	    await db.sessions_charging.update(sessionId, { status: 'Active' });
51	    await completeSession(sessionId, actor);
52	  } else {
53	    const now = Date.now();
54	    await db.sessions_charging.update(sessionId, {
55	      status: 'Completed',
56	      endedAt: now,
57	      anomalyReason: `${session.anomalyReason ?? ''} | cancelled: ${reason}`,
58	      version: session.version + 1
59	    });
60	    await db.reservations.update(session.reservationId, { status: 'Cancelled' });
61	    await db.bays.update(session.bayId, { status: 'Available' });
62	  }
63	
64	  await auditService.log(actor, 'ANOMALY_RESOLVED', 'ChargingSession', sessionId, {
65	    resolution,
66	    reason
67	  });
68	}
