1	import { useEffect, useState } from 'react';
2	import { BrowserRouter } from 'react-router-dom';
3	import { AuthProvider, useAuth } from './hooks/useAuth';
4	import { heartbeatService } from './services/heartbeatService';
5	import { notificationService } from './services/notificationService';
6	import { qualityService } from './services/qualityService';
7	import { reservationService } from './services/reservationService';
8	import { tieringService } from './services/tieringService';
9	import { AppRouter } from './router';
10	
11	function Runtime() {
12	  const { currentUser } = useAuth();
13	  const [banner, setBanner] = useState<string | null>(null);
14	
15	  useEffect(() => {
16	    if (!currentUser) {
17	      return;
18	    }
19	
20	    const siteId = currentUser.siteId;
21	    if (siteId) {
22	      void qualityService.runWeeklyIfDue(siteId, currentUser);
23	      void tieringService.runTiering(siteId, currentUser);
24	    }
25	
26	    const heartbeatTimer = window.setInterval(() => {
27	      void heartbeatService.tick(currentUser);
28	    }, 30_000);
29	
30	    const anomalyTimer = window.setInterval(() => {
31	      void heartbeatService.checkAnomalies(currentUser);
32	    }, 60_000);
33	
34	    const noShowTimer = window.setInterval(() => {
35	      void reservationService.autoProcessNoShows(currentUser);
36	    }, 60_000);
37	
38	    const notifRetryTimer = window.setInterval(() => {
39	      void notificationService.retryFailed();
40	    }, 30_000);
41	
42	    const notifRuleTimer = window.setInterval(() => {
43	      void notificationService.runDueAndOverdueSchedulers(currentUser);
44	    }, 60_000);
45	
46	    const clearBanner = window.setInterval(() => setBanner(null), 5_000);
47	    const tieringTimer = window.setInterval(() => {
48	      if (siteId) {
49	        void tieringService.runTiering(siteId, currentUser);
50	      }
51	    }, 24 * 60 * 60 * 1000);
52	    notificationService.setBannerListener((subject, userId) => {
53	      if (currentUser.id === userId) {
54	        setBanner(subject);
55	      }
56	    });
57	
58	    return () => {
59	      window.clearInterval(heartbeatTimer);
60	      window.clearInterval(anomalyTimer);
61	      window.clearInterval(noShowTimer);
62	      window.clearInterval(notifRetryTimer);
63	      window.clearInterval(notifRuleTimer);
64	      window.clearInterval(clearBanner);
65	      window.clearInterval(tieringTimer);
66	      notificationService.setBannerListener(null);
67	    };
68	  }, [currentUser]);
69	
70	  if (!banner) {
71	    return null;
72	  }
73	
74	  return <div className="notif-banner">{banner}</div>;
75	}
76	
77	function App() {
78	  return (
79	    <AuthProvider>
80	      <BrowserRouter>
81	        <Runtime />
82	        <AppRouter />
83	      </BrowserRouter>
84	    </AuthProvider>
85	  );
86	}
87	
88	export default App;
