5	
6	interface TableStat {
7	  table: string;
8	  totalRows: number;
9	  missingFieldRows: number;
10	  completenessPct: number;
11	  duplicateRows: number;
12	}
13	
14	interface ReportDetail {
15	  generatedAt: number;
16	  stats: TableStat[];
17	}
18	
19	function completeness(total: number, missing: number): number {
20	  if (total === 0) {
21	    return 100;
22	  }
23	  return Number((((total - missing) / total) * 100).toFixed(2));
24	}
25	
26	async function runReport(siteId: number, actor: User): Promise<QualityReport> {
27	  const reservations = await db.reservations.where('siteId').equals(siteId).toArray();
28	  const orders = await db.orders.where('siteId').equals(siteId).toArray();
29	  const sessions = await db.sessions_charging.where('siteId').equals(siteId).toArray();
30	
31	  const reservationMissing = reservations.filter((r) => !r.customerName || !r.customerPlate).length;
32	  const orderMissing = orders.filter((o) => !o.orderNumber).length;
33	  const sessionMissing = sessions.filter((s) => !s.reservationId || !s.startedAt).length;
34	
35	  const reservationKeyCount = new Map<string, number>();
36	  reservations.forEach((r) => {
37	    const key = `${r.bayId}_${r.scheduledStart}`;
38	    reservationKeyCount.set(key, (reservationKeyCount.get(key) ?? 0) + 1);
39	  });
40	  const reservationDuplicates = [...reservationKeyCount.values()].filter((count) => count > 1).length;
41	
42	  const orderKeyCount = new Map<string, number>();
43	  orders.forEach((o) => {
44	    orderKeyCount.set(o.orderNumber, (orderKeyCount.get(o.orderNumber) ?? 0) + 1);
45	  });
46	  const orderDuplicates = [...orderKeyCount.values()].filter((count) => count > 1).length;
47	
48	  const stats: TableStat[] = [
49	    {
50	      table: 'reservations',
51	      totalRows: reservations.length,
52	      missingFieldRows: reservationMissing,
53	      completenessPct: completeness(reservations.length, reservationMissing),
54	      duplicateRows: reservationDuplicates
55	    },
56	    {
57	      table: 'orders',
58	      totalRows: orders.length,
59	      missingFieldRows: orderMissing,
60	      completenessPct: completeness(orders.length, orderMissing),
61	      duplicateRows: orderDuplicates
62	    },
63	    {
64	      table: 'sessions_charging',
65	      totalRows: sessions.length,
66	      missingFieldRows: sessionMissing,
67	      completenessPct: completeness(sessions.length, sessionMissing),
68	      duplicateRows: 0
69	    }
70	  ];
71	
72	  const detail: ReportDetail = {
73	    generatedAt: Date.now(),
74	    stats
75	  };
76	
77	  const reportId = await db.qualityReports.add({
78	    siteId,
79	    generatedAt: detail.generatedAt,
80	    type: 'Weekly',
81	    detail: JSON.stringify(detail)
82	  });
83	  await auditService.log(actor, 'QUALITY_REPORT_GENERATED', 'QualityReport', reportId);
84	
85	  const recipients = await db.users.where('siteId').equals(siteId).toArray();
86	  for (const user of recipients) {
87	    if (user.role === 'SiteManager') {
88	      await notificationService.send(user.id as number, 'QUALITY_REPORT_READY', {
89	        siteName: String(siteId),
90	        issues: String(stats.reduce((acc, row) => acc + row.missingFieldRows + row.duplicateRows, 0))
91	      });
92	    }
93	  }
94	  const sysAdmins = await db.users.where('role').equals('SystemAdministrator').toArray();
95	  for (const admin of sysAdmins) {
96	    await notificationService.send(admin.id as number, 'QUALITY_REPORT_READY', {
97	      siteName: String(siteId),
98	      issues: String(stats.reduce((acc, row) => acc + row.missingFieldRows + row.duplicateRows, 0))
99	    });
100	  }
101	
102	  return (await db.qualityReports.get(reportId)) as QualityReport;
103	}
104	
105	function exportReportCsv(report: QualityReport): void {
106	  const detail = JSON.parse(report.detail) as ReportDetail;
107	  const lines = [
108	    'table,completeness_pct,total_rows,missing_field_rows,duplicate_rows',
109	    ...detail.stats.map(
110	      (row) =>
111	        `${row.table},${row.completenessPct},${row.totalRows},${row.missingFieldRows},${row.duplicateRows}`
112	    )
113	  ];
114	
115	  const blob = new Blob([lines.join('\n')], { type: 'text/csv' });
116	  const url = URL.createObjectURL(blob);
117	  const a = document.createElement('a');
118	  a.href = url;
119	  a.download = `quality_report_${report.siteId}_${report.generatedAt}.csv`;
120	  a.click();
121	  URL.revokeObjectURL(url);
122	}
123	
124	async function runWeeklyIfDue(siteId: number, actor: User): Promise<boolean> {
125	  const key = `cb_quality_lastRun_${siteId}`;
126	  const now = Date.now();
127	  const lastRun = Number(localStorage.getItem(key) ?? 0);
128	  if (now - lastRun <= 7 * 24 * 60 * 60 * 1000) {
129	    return false;
130	  }
131	
132	  await runReport(siteId, actor);
133	  localStorage.setItem(key, String(now));
134	  return true;
135	}
136	
137	export const qualityService = {
138	  runReport,
139	  exportReportCsv,
140	  runWeeklyIfDue
141	};
