5	export interface TieringResult {
6	  reservationsArchived: number;
7	  sessionsArchived: number;
8	  ordersArchived: number;
9	}
10	
11	async function runTiering(siteId: number, actor: User): Promise<TieringResult> {
12	  const cutoff = Date.now() - 90 * 24 * 60 * 60 * 1000;
13	  let reservationsArchived = 0;
14	  let sessionsArchived = 0;
15	  let ordersArchived = 0;
16	
17	  const reservations = await db.reservations
18	    .where('siteId')
19	    .equals(siteId)
20	    .filter((r) => r.scheduledStart < cutoff)
21	    .toArray();
22	  await db.transaction('rw', db.reservations, db.reservations_cold, async () => {
23	    for (const row of reservations) {
24	      await db.reservations_cold.add({
25	        bayId: row.bayId,
26	        siteId,
27	        originalId: row.id as number,
28	        archivedAt: Date.now()
29	      });
30	      await db.reservations.delete(row.id as number);
31	      reservationsArchived += 1;
32	    }
33	  });
34	
35	  const sessions = await db.sessions_charging
36	    .where('siteId')
37	    .equals(siteId)
38	    .filter((s) => s.startedAt < cutoff)
39	    .toArray();
40	  await db.transaction('rw', db.sessions_charging, db.sessions_cold, async () => {
41	    for (const row of sessions) {
42	      await db.sessions_cold.add({
43	        bayId: row.bayId,
44	        siteId,
45	        originalId: row.id as number,
46	        archivedAt: Date.now()
47	      });
48	      await db.sessions_charging.delete(row.id as number);
49	      sessionsArchived += 1;
50	    }
51	  });
52	
53	  const orders = await db.orders
54	    .where('siteId')
55	    .equals(siteId)
56	    .filter((o) => (o as { createdAt?: number }).createdAt ? (o as { createdAt: number }).createdAt < cutoff : false)
57	    .toArray();
58	  await db.transaction('rw', db.orders, db.orders_cold, async () => {
59	    for (const row of orders) {
60	      await db.orders_cold.add({
61	        siteId,
62	        originalId: row.id as number,
63	        archivedAt: Date.now()
64	      });
65	      await db.orders.delete(row.id as number);
66	      ordersArchived += 1;
67	    }
68	  });
69	
70	  localStorage.setItem(
71	    `cb_tiering_last_${siteId}`,
72	    JSON.stringify({
73	      ranAt: Date.now(),
74	      reservationsArchived,
75	      sessionsArchived,
76	      ordersArchived
77	    })
78	  );
79	  await auditService.log(actor, 'TIERING_RUN', 'Site', siteId, {
80	    reservationsArchived,
81	    sessionsArchived,
82	    ordersArchived
83	  });
84	
85	  return { reservationsArchived, sessionsArchived, ordersArchived };
86	}
87	
88	async function queryColdReservations(siteId: number): Promise<Array<{ originalId: number; archivedAt: number }>> {
89	  const rows = await db.reservations_cold.where('siteId').equals(siteId).toArray();
90	  return rows.map((row) => ({ originalId: row.originalId, archivedAt: row.archivedAt }));
91	}
92	
93	export const tieringService = {
94	  runTiering,
95	  queryColdReservations
96	};
