6	interface CreateUserInput {
7	  username: string;
8	  password: string;
9	  role: UserRole;
10	  siteId?: number;
11	}
12	
13	function assertSystemAdministrator(actor: User) {
14	  if (actor.role !== 'SystemAdministrator') {
15	    throw new Error('RBAC_SCOPE_VIOLATION');
16	  }
17	}
18	
19	async function listUsers(actor: User): Promise<User[]> {
20	  assertSystemAdministrator(actor);
21	  return db.users.orderBy('username').toArray();
22	}
23	
24	async function createUser(actor: User, input: CreateUserInput): Promise<number> {
25	  assertSystemAdministrator(actor);
26	  const existing = await db.users.where('username').equals(input.username).first();
27	  if (existing) {
28	    throw new Error('USER_ALREADY_EXISTS');
29	  }
30	
31	  const { hash, salt } = await cryptoService.hashPassword(input.password);
32	  const createdUser: User = {
33	    username: input.username,
34	    passwordHash: hash,
35	    salt,
36	    role: input.role,
37	    siteId: input.role === 'SystemAdministrator' ? undefined : input.siteId,
38	    failedAttempts: 0,
39	    lockedUntil: undefined
40	  };
41	
42	  const userId = await db.users.add(createdUser);
43	  await auditService.log(actor, 'USER_CREATED', 'User', userId, {
44	    username: input.username,
45	    role: input.role,
46	    siteId: createdUser.siteId
47	  });
48	
49	  return userId;
50	}
51	
52	async function resetPassword(actor: User, userId: number, newPassword: string): Promise<void> {
53	  assertSystemAdministrator(actor);
54	  const user = await db.users.get(userId);
55	  if (!user) {
56	    throw new Error('USER_NOT_FOUND');
57	  }
58	
59	  const { hash, salt } = await cryptoService.hashPassword(newPassword);
60	  await db.users.update(userId, {
61	    passwordHash: hash,
62	    salt,
63	    failedAttempts: 0,
64	    lockedUntil: undefined
65	  });
66	  await auditService.log(actor, 'USER_PASSWORD_RESET', 'User', userId, {
67	    username: user.username
68	  });
69	}
70	
71	async function unlockAccount(actor: User, userId: number): Promise<void> {
72	  assertSystemAdministrator(actor);
73	  const user = await db.users.get(userId);
74	  if (!user) {
75	    throw new Error('USER_NOT_FOUND');
76	  }
77	
78	  await db.users.update(userId, {
79	    failedAttempts: 0,
80	    lockedUntil: undefined
81	  });
82	  await auditService.log(actor, 'USER_UNLOCKED', 'User', userId, {
83	    username: user.username
84	  });
85	}
