2	import type { Bay, Site, User, UserRole } from '../types';
3	import { cryptoService } from '../services/cryptoService';
4	
5	const DEMO_USERS: Array<{ username: string; password: string; role: UserRole; siteId?: number }> = [
6	  { username: 'sysadmin', password: 'ChargeBay#Admin1', role: 'SystemAdministrator' },
7	  { username: 'manager', password: 'ChargeBay#Mgr01', role: 'SiteManager', siteId: 1 },
8	  { username: 'attendant', password: 'ChargeBay#Att01', role: 'Attendant', siteId: 1 },
9	  { username: 'auditor', password: 'ChargeBay#Aud01', role: 'Auditor', siteId: 1 }
10	];
11	
12	async function seedUsers() {
13	  const users: User[] = [];
14	
15	  for (const user of DEMO_USERS) {
16	    const { hash, salt } = await cryptoService.hashPassword(user.password);
17	    users.push({
18	      username: user.username,
19	      passwordHash: hash,
20	      salt,
21	      role: user.role,
22	      siteId: user.siteId,
23	      failedAttempts: 0
24	    });
25	  }
26	
27	  await db.users.bulkAdd(users);
28	}
29	
30	async function seedSiteAndBays() {
31	  const site: Site = { siteCode: 'SITE-001', name: 'ChargeBay Site 1' };
32	  const siteId = await db.sites.add(site);
33	
34	  const bays: Bay[] = ['ST-01', 'ST-02', 'ST-03', 'ST-04'].map((stationId, index) => ({
35	    siteId,
36	    stationId,
37	    connectorId: 'C1',
38	    label: `Bay ${index + 1}`,
39	    status: 'Available'
40	  }));
41	
42	  await db.bays.bulkAdd(bays);
43	}
