45	async function migrateLegacySeedUsers() {
46	  const users = await db.users.toArray();
47	  const demoPasswordByUsername = new Map(DEMO_USERS.map((entry) => [entry.username, entry.password]));
48	
49	  for (const user of users) {
50	    if (user.salt) {
51	      continue;
52	    }
53	
54	    const password = demoPasswordByUsername.get(user.username);
55	    if (!password || !user.id) {
56	      continue;
57	    }
58	
59	    const { hash, salt } = await cryptoService.hashPassword(password);
60	    await db.users.update(user.id, { passwordHash: hash, salt, failedAttempts: 0, lockedUntil: undefined });
61	  }
62	}
