            setType(next);
            setFile(null);
            setHeaders([]);
            setFieldMap({});
            setSummary(null);
          }}
        >
          <option value="reservations">reservations</option>
          <option value="orders">orders</option>
          <option value="sessions">sessions</option>
        </select>
        <button className="button ghost" onClick={() => importService.downloadTemplate(type)}>
