1	import { FormEvent, useEffect, useState } from 'react';
2	import { useLocation, useNavigate } from 'react-router-dom';
3	import { useAuth } from '../hooks/useAuth';
4	import { AuthLockedError, AuthWrongPasswordError } from '../services/authService';
5	
6	export default function LoginPage() {
7	  const { currentUser, login, navMode } = useAuth();
8	  const navigate = useNavigate();
9	  const location = useLocation();
10	
11	  const [username, setUsername] = useState('');
12	  const [password, setPassword] = useState('');
13	  const [error, setError] = useState<string | null>(null);
14	
15	  useEffect(() => {
16	    if (!currentUser) {
17	      return;
18	    }
19	
20	    const returnTo = (location.state as { returnTo?: string } | null)?.returnTo;
21	    navigate(returnTo ?? (navMode === 'kiosk' ? '/kiosk' : '/admin/dashboard'), { replace: true });
22	  }, [currentUser, location.state, navigate, navMode]);
23	
24	  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
25	    event.preventDefault();
26	    setError(null);
27	
28	    try {
29	      await login(username.trim(), password);
30	    } catch (submitError) {
31	      let message = 'Login failed';
32	      if (submitError instanceof AuthWrongPasswordError) {
33	        message = 'Invalid username or password';
34	      } else if (submitError instanceof AuthLockedError) {
35	        const minutes = Math.max(1, Math.ceil(submitError.remainingMs / 60_000));
36	        message = `Account locked. Try again in ${minutes} minutes.`;
37	      }
38	      setError(message);
39	    }
40	  };
41	
42	  return (
43	    <section className="login-page">
44	      <form className="card login-card" onSubmit={handleSubmit}>
45	        <h1>ChargeBay Offline Operations Console</h1>
46	        <p>Sign in with your local account.</p>
47	
48	        <label htmlFor="username">Username</label>
49	        <input
50	          id="username"
51	          name="username"
52	          value={username}
53	          onChange={(event) => setUsername(event.target.value)}
54	          autoComplete="username"
55	          required
56	        />
57	
58	        <label htmlFor="password">Password</label>
59	        <input
60	          id="password"
61	          name="password"
62	          type="password"
63	          value={password}
64	          onChange={(event) => setPassword(event.target.value)}
65	          autoComplete="current-password"
66	          required
67	        />
68	
69	        {error ? <p className="error">{error}</p> : null}
70	
71	        <button className="button primary" type="submit">
72	          Login
73	        </button>
74	      </form>
75	    </section>
76	  );
77	}
