{"file_path": "/Users/apple/Documents/projects/eagle-point_new/TASK-121/repo/src/db/seed.ts", "content": "import { db } from './db';
import type { Bay, Site, User, UserRole } from '../types';
import { cryptoService } from '../services/cryptoService';

const DEMO_USERS: Array<{ username: string; password: string; role: UserRole; siteId?: number }> = [
  { username: 'sysadmin', password: 'ChargeBay#Admin1', role: 'SystemAdministrator' },
  { username: 'manager', password: 'ChargeBay#Mgr01', role: 'SiteManager', siteId: 1 },
  { username: 'attendant', password: 'ChargeBay#Att01', role: 'Attendant', siteId: 1 },
  { username: 'auditor', password: 'ChargeBay#Aud01', role: 'Auditor', siteId: 1 }
];

async function seedUsers() {
  // Hash passwords OUTSIDE the transaction to avoid PrematureCommitError
  // (WebCrypto operations break IndexedDB transaction scope)
  const users: User[] = [];

  for (const user of DEMO_USERS) {
    const { hash, salt } = await cryptoService.hashPassword(user.password);
    users.push({
      username: user.username,
      passwordHash: hash,
      salt,
      role: user.role,
      siteId: user.siteId,
      failedAttempts: 0
    });
  }

  await db.users.bulkAdd(users);
}

async function seedSiteAndBays() {
  const site: Site = { siteCode: 'SITE-001', name: 'ChargeBay Site 1' };
  const siteId = await db.sites.add(site);

  const bays: Bay[] = ['ST-01', 'ST-02', 'ST-03', 'ST-04'].map((stationId, index) => ({
    siteId,
    stationId,
    connectorId: 'C1',
    label: `Bay ${index + 1}`,
    status: 'Available'
  }));

  await db.bays.bulkAdd(bays);
}

async function migrateLegacySeedUsers() {
  const users = await db.users.toArray();
  const demoPasswordByUsername = new Map(DEMO_USERS.map((entry) => [entry.username, entry.password]));

  // Do all crypto work first, outside any transaction
  const updates: Array<{ id: number; hash: string; salt: string }> = [];
  for (const user of users) {
    if (user.salt) {
      continue;
    }

    const password = demoPasswordByUsername.get(user.username);
    if (!password || !user.id) {
      continue;
    }

    const { hash, salt } = await cryptoService.hashPassword(password);
    updates.push({ id: user.id, hash, salt });
  }

  // Apply updates (no crypto inside DB operations)
  for (const update of updates) {
    await db.users.update(update.id, {
      passwordHash: update.hash,
      salt: update.salt,
      failedAttempts: 0,
      lockedUntil: undefined
    });
  }
}

export async function seedIfEmpty() {
  const userCount = await db.users.count();
  if (userCount > 0) {
    await migrateLegacySeedUsers();
    return;
  }

  // Seed site and bays first (no crypto needed)
  await seedSiteAndBays();
  // Then seed users (crypto done outside transaction)
  await seedUsers();
}
"}

