385	        if (type === 'orders') {
386	          const dup = await db.orders
387	            .where('siteId')
388	            .equals(actor.siteId as number)
389	            .filter((o) => o.orderNumber === row.orderNumber)
390	            .first();
391	          if (dup) {
392	            isDuplicate = true;
393	          } else {
394	            const duration = Number(row.durationMinutes);
395	            const rate = Number(row.ratePerMinute);
396	            const adjustment = Number(row.adjustmentAmount);
397	            const subtotal = Number((duration * rate).toFixed(2));
398	            const encNotes = encryptedRows[index]?.encNotes ?? row.invoiceNotes;
399	            await db.orders.add({
