65	function Runtime() {
66	  const { currentUser } = useAuth();
67	  const [banner, setBanner] = useState<string | null>(null);
68	
69	  useEffect(() => {
70	    if (!currentUser) {
71	      return;
72	    }
73	
74	    const siteId = currentUser.siteId;
75	    const canMutate = currentUser.role !== 'Auditor';
76	    if (siteId && canMutate) {
77	      void qualityService.runWeeklyIfDue(siteId, currentUser);
78	      void tieringService.runTiering(siteId, currentUser);
79	    }
80	
81	    const heartbeatTimer = window.setInterval(() => {
82	      void heartbeatService.tick(currentUser);
83	    }, 30_000);
84	
85	    const anomalyTimer = window.setInterval(() => {
86	      void heartbeatService.checkAnomalies(currentUser);
87	    }, 60_000);
88	
89	    const noShowTimer = window.setInterval(() => {
90	      void reservationService.autoProcessNoShows(currentUser);
91	    }, 60_000);
92	
93	    const notifRetryTimer = window.setInterval(() => {
94	      void notificationService.retryFailed();
95	    }, 30_000);
96	
97	    const notifRuleTimer = window.setInterval(() => {
98	      void notificationService.runDueAndOverdueSchedulers(currentUser);
99	    }, 60_000);
100	
101	    const clearBanner = window.setInterval(() => setBanner(null), 5_000);
102	    const tieringTimer = window.setInterval(() => {
103	      if (siteId && canMutate) {
104	        void tieringService.runTiering(siteId, currentUser);
105	      }
106	    }, 24 * 60 * 60 * 1000);
107	    notificationService.setBannerListener((subject, userId) => {
108	      if (currentUser.id === userId) {
109	        setBanner(subject);
110	      }
111	    });
112	
113	    return () => {
114	      window.clearInterval(heartbeatTimer);
115	      window.clearInterval(anomalyTimer);
116	      window.clearInterval(noShowTimer);
117	      window.clearInterval(notifRetryTimer);
118	      window.clearInterval(notifRuleTimer);
119	      window.clearInterval(clearBanner);
120	      window.clearInterval(tieringTimer);
121	      notificationService.setBannerListener(null);
122	    };
123	  }, [currentUser]);
124	
125	  if (!banner) {
126	    return null;
127	  }
128	
129	  return <div className="notif-banner">{banner}</div>;
130	}
