6	async function tick(actor: User): Promise<void> {
7	  const now = Date.now();
8	  const sessions = await db.sessions_charging
9	    .where('status')
10	    .equals('Active')
11	    .filter((session) =>
12	      actor.role === 'SystemAdministrator' ? true : session.siteId === actor.siteId
13	    )
14	    .toArray();
15	
16	  for (const session of sessions) {
17	    await db.sessions_charging.update(session.id as number, {
18	      heartbeatAt: now,
19	      version: session.version + 1
20	    });
21	  }
22	}
