24	async function checkAnomalies(actor: User): Promise<void> {
25	  const siteId = actor.siteId;
26	  const now = Date.now();
27	
28	  const targetSites =
29	    actor.role === 'SystemAdministrator'
30	      ? await db.sites.toArray().then((sites) => sites.map((site) => site.id as number))
31	      : [siteId as number];
32	
33	  for (const currentSiteId of targetSites) {
34	    const config = siteConfigService.getSiteConfig(currentSiteId);
35	    const heartbeatCutoff = now - config.anomalyHeartbeatTimeoutMin * 60_000;
36	    const tempLeaveCutoff = now - config.tempLeaveMaxMinutes * 60_000;
37	
38	    const noHeartbeat = await db.sessions_charging
39	      .where('status')
40	      .equals('Active')
41	      .filter((session) => session.siteId === currentSiteId && session.heartbeatAt < heartbeatCutoff)
42	      .toArray();
43	
44	    for (const session of noHeartbeat) {
45	      await reservationService.flagAnomaly(session.id as number, 'No heartbeat for 30+ minutes', actor);
46	    }
47	
48	    const tempLeaveExceeded = await db.sessions_charging
49	      .where('status')
50	      .equals('TempLeave')
51	      .filter(
52	        (session) =>
53	          session.siteId === currentSiteId &&
54	          typeof session.tempLeaveStartedAt === 'number' &&
55	          session.tempLeaveStartedAt < tempLeaveCutoff
56	      )
57	      .toArray();
58	
59	    for (const session of tempLeaveExceeded) {
60	      await reservationService.flagAnomaly(session.id as number, 'Temp leave duration exceeded', actor);
61	    }
62	  }
63	}
