37	export function AuthProvider({ children }: PropsWithChildren) {
38	  const [currentUser, setCurrentUser] = useState<User | null>(null);
39	  const [encryptionKey, setEncryptionKey] = useState<CryptoKey | null>(null);
40	  const [isRestoringSession, setIsRestoringSession] = useState(true);
41	  const [needsUnlock, setNeedsUnlock] = useState(false);
42	
43	  useEffect(() => {
44	    const restore = async () => {
45	      try {
46	        const user = await authService.restoreSession();
47	        if (user) {
48	          setCurrentUser(user);
49	          setNeedsUnlock(true);
50	        }
51	      } finally {
52	        setIsRestoringSession(false);
53	      }
54	    };
55	
56	    void restore();
57	  }, []);
58	
59	  const login = useCallback(async (username: string, password: string) => {
60	    const { user, encryptionKey: key } = await authService.login(username, password);
61	    setCurrentUser(user);
62	    setEncryptionKey(key);
63	    setNeedsUnlock(false);
64	  }, []);
65	
66	  const logout = useCallback(() => {
67	    authService.logout();
68	    setCurrentUser(null);
69	    setEncryptionKey(null);
70	    setNeedsUnlock(false);
71	  }, []);
72	
73	  const unlock = useCallback(
74	    async (password: string) => {
75	      if (!currentUser) {
76	        throw new Error('No user to unlock');
77	      }
78	      const isValid = await cryptoService.verifyPassword(
79	        password,
80	        currentUser.passwordHash,
81	        currentUser.salt
82	      );
83	      if (!isValid) {
84	        throw new Error('AUTH_WRONG_PASSWORD');
85	      }
86	      const key = await cryptoService.deriveEncryptionKey(password, currentUser.salt);
87	      setEncryptionKey(key);
88	      setNeedsUnlock(false);
89	    },
90	    [currentUser]
91	  );
92	
93	  const hasRole = useCallback(
94	    (...roles: UserRole[]) => {
95	      if (!currentUser) {
96	        return false;
97	      }
98	
99	      return roles.includes(currentUser.role);
100	    },
101	    [currentUser]
102	  );
103	
104	  const value = useMemo<AuthContextValue>(
105	    () => ({
106	      currentUser,
107	      navMode: deriveNavMode(currentUser),
108	      isRestoringSession,
109	      needsUnlock,
110	      login,
111	      logout,
112	      unlock,
113	      hasRole,
114	      encryptionKey
115	    }),
116	    [currentUser, encryptionKey, hasRole, isRestoringSession, needsUnlock, login, logout, unlock]
117	  );
118	
119	  return createElement(AuthContext.Provider, { value }, children);
120	}
