1	import { db } from '../db/db';
2	import type { User } from '../types';
3	import { auditService } from './auditService';
4	import { assertCanMutate } from './rbacService';
5	
6	export interface TieringResult {
7	  reservationsArchived: number;
8	  sessionsArchived: number;
9	  ordersArchived: number;
10	}
11	
12	async function runTiering(siteId: number, actor: User): Promise<TieringResult> {
13	  assertCanMutate(actor);
14	  const cutoff = Date.now() - 90 * 24 * 60 * 60 * 1000;
15	  let reservationsArchived = 0;
16	  let sessionsArchived = 0;
17	  let ordersArchived = 0;
18	
19	  const reservations = await db.reservations
20	    .where('siteId')
21	    .equals(siteId)
22	    .filter((r) => r.scheduledStart < cutoff)
23	    .toArray();
24	  await db.transaction('rw', db.reservations, db.reservations_cold, async () => {
25	    for (const row of reservations) {
26	      await db.reservations_cold.add({
27	        bayId: row.bayId,
28	        siteId,
29	        originalId: row.id as number,
30	        archivedAt: Date.now()
31	      });
32	      await db.reservations.delete(row.id as number);
33	      reservationsArchived += 1;
34	    }
35	  });
36	
37	  const sessions = await db.sessions_charging
38	    .where('siteId')
39	    .equals(siteId)
40	    .filter((s) => s.startedAt < cutoff)
41	    .toArray();
42	  await db.transaction('rw', db.sessions_charging, db.sessions_cold, async () => {
43	    for (const row of sessions) {
44	      await db.sessions_cold.add({
45	        bayId: row.bayId,
46	        siteId,
47	        originalId: row.id as number,
48	        archivedAt: Date.now()
49	      });
50	      await db.sessions_charging.delete(row.id as number);
51	      sessionsArchived += 1;
52	    }
53	  });
54	
55	  const orders = await db.orders
56	    .where('siteId')
57	    .equals(siteId)
58	    .filter((o) => (o as { createdAt?: number }).createdAt ? (o as { createdAt: number }).createdAt < cutoff : false)
59	    .toArray();
60	  await db.transaction('rw', db.orders, db.orders_cold, async () => {
61	    for (const row of orders) {
62	      await db.orders_cold.add({
63	        siteId,
64	        originalId: row.id as number,
65	        archivedAt: Date.now()
66	      });
67	      await db.orders.delete(row.id as number);
68	      ordersArchived += 1;
69	    }
70	  });
71	
72	  localStorage.setItem(
73	    `cb_tiering_last_${siteId}`,
74	    JSON.stringify({
75	      ranAt: Date.now(),
76	      reservationsArchived,
77	      sessionsArchived,
78	      ordersArchived
79	    })
80	  );
81	  await auditService.log(actor, 'TIERING_RUN', 'Site', siteId, {
82	    reservationsArchived,
83	    sessionsArchived,
84	    ordersArchived
85	  });
86	
87	  return { reservationsArchived, sessionsArchived, ordersArchived };
88	}
89	
90	async function queryColdReservations(siteId: number): Promise<Array<{ originalId: number; archivedAt: number }>> {
91	  const rows = await db.reservations_cold.where('siteId').equals(siteId).toArray();
92	  return rows.map((row) => ({ originalId: row.originalId, archivedAt: row.archivedAt }));
93	}
94	
95	export const tieringService = {
96	  runTiering,
97	  queryColdReservations
98	};
