2	import type { User } from '../types';
3	import { auditService } from './auditService';
4	import { cryptoService } from './cryptoService';
5	import { assertCanMutate } from './rbacService';
6	
7	interface DateRange {
8	  from: number;
9	  to: number;
10	}
11	
12	interface ExportPackage {
13	  version: 1;
14	  siteId: number;
15	  exportedAt: number;
16	  exportedBy: string;
17	  dateRange: DateRange;
18	  signature: string;
19	  salt: string;
20	  iv: string;
21	  ciphertext: string;
22	}
23	
24	function bytesToHex(bytes: Uint8Array): string {
25	  return [...bytes].map((b) => b.toString(16).padStart(2, '0')).join('');
26	}
27	
28	function hexToBytes(hex: string): Uint8Array {
29	  const out = new Uint8Array(hex.length / 2);
30	  for (let index = 0; index < out.length; index += 1) {
31	    out[index] = Number.parseInt(hex.slice(index * 2, index * 2 + 2), 16);
32	  }
33	  return out;
34	}
35	
36	function bytesToBase64(bytes: Uint8Array): string {
37	  let binary = '';
38	  for (const byte of bytes) binary += String.fromCharCode(byte);
39	  return btoa(binary);
40	}
41	
42	function base64ToBytes(base64: string): Uint8Array {
43	  const binary = atob(base64);
44	  const out = new Uint8Array(binary.length);
45	  for (let i = 0; i < binary.length; i += 1) out[i] = binary.charCodeAt(i);
46	  return out;
47	}
48	
49	async function sha256Hex(value: string): Promise<string> {
50	  const digest = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(value));
51	  return bytesToHex(new Uint8Array(digest));
52	}
53	
54	async function exportPackage(
55	  siteId: number,
56	  dateRange: DateRange,
57	  password: string,
58	  actor: User
59	): Promise<Blob> {
60	  assertCanMutate(actor);
61	  const [reservations, sessions, orders, reservationsCold, sessionsCold, ordersCold] = await Promise.all([
62	    db.reservations
63	      .where('siteId')
64	      .equals(siteId)
65	      .filter((r) => r.scheduledStart >= dateRange.from && r.scheduledStart <= dateRange.to)
66	      .toArray(),
67	    db.sessions_charging
68	      .where('siteId')
69	      .equals(siteId)
70	      .filter((s) => s.startedAt >= dateRange.from && s.startedAt <= dateRange.to)
71	      .toArray(),
72	    db.orders.where('siteId').equals(siteId).toArray(),
73	    db.reservations_cold.where('siteId').equals(siteId).toArray(),
74	    db.sessions_cold.where('siteId').equals(siteId).toArray(),
75	    db.orders_cold.where('siteId').equals(siteId).toArray()
76	  ]);
77	
78	  const payload = JSON.stringify({
79	    reservations,
80	    sessions,
81	    orders,
82	    reservationsCold,
83	    sessionsCold,
84	    ordersCold
85	  });
86	  const signature = await sha256Hex(payload + password);
87	  const salt = bytesToHex(crypto.getRandomValues(new Uint8Array(16)));
88	  const key = await cryptoService.deriveEncryptionKey(password, salt);
89	  const iv = crypto.getRandomValues(new Uint8Array(12));
90	  const cipher = await crypto.subtle.encrypt(
91	    { name: 'AES-GCM', iv },
92	    key,
93	    new TextEncoder().encode(payload)
94	  );
95	
96	  const pkg: ExportPackage = {
97	    version: 1,
98	    siteId,
99	    exportedAt: Date.now(),
100	    exportedBy: actor.username,
101	    dateRange,
102	    signature,
103	    salt,
104	    iv: bytesToHex(iv),
105	    ciphertext: bytesToBase64(new Uint8Array(cipher))
106	  };
107	
108	  const json = JSON.stringify(pkg, null, 2);
109	  const blob = new Blob([json], { type: 'application/json' });
110	  const url = URL.createObjectURL(blob);
111	  const site = await db.sites.get(siteId);
112	  const a = document.createElement('a');
113	  a.href = url;
114	  a.download = `cb-export-${site?.siteCode ?? siteId}-${new Date().toISOString().slice(0, 10)}.json`;
115	  a.click();
116	  URL.revokeObjectURL(url);
117	
118	  await auditService.log(actor, 'EXPORT_PACKAGE_CREATED', 'Site', siteId);
119	  return blob;
120	}
