122	async function importPackage(file: File, password: string, actor: User): Promise<{ inserted: number; skipped: number }> {
123	  assertCanMutate(actor);
124	  const text =
125	    'text' in file
126	      ? await (file as unknown as { text: () => Promise<string> }).text()
127	      : await new Promise<string>((resolve, reject) => {
128	          const reader = new FileReader();
129	          reader.onload = () => resolve(String(reader.result ?? ''));
130	          reader.onerror = () => reject(reader.error);
131	          reader.readAsText(file);
132	        });
