134	  const pkg = JSON.parse(text) as ExportPackage;
135	  if (pkg.version !== 1) {
136	    throw new Error('EXPORT_SIGNATURE_MISMATCH');
137	  }
138	
139	  try {
140	    const key = await cryptoService.deriveEncryptionKey(password, pkg.salt);
141	    const iv = hexToBytes(pkg.iv);
142	    const plain = await crypto.subtle.decrypt(
143	      { name: 'AES-GCM', iv: iv as unknown as BufferSource },
144	      key,
145	      base64ToBytes(pkg.ciphertext) as unknown as BufferSource
146	    );
147	    const payloadText = new TextDecoder().decode(plain);
148	    const signature = await sha256Hex(payloadText + password);
149	    if (signature !== pkg.signature) {
150	      throw new Error('EXPORT_SIGNATURE_MISMATCH');
151	    }
