153	    const payload = JSON.parse(payloadText) as {
154	      reservations: Array<{ id?: number }>;
155	      sessions: Array<{ id?: number }>;
156	      orders: Array<{ id?: number }>;
157	      reservationsCold: Array<{ id?: number }>;
158	      sessionsCold: Array<{ id?: number }>;
159	      ordersCold: Array<{ id?: number }>;
160	    };
161	
162	    let inserted = 0;
163	    let skipped = 0;
164	    for (const row of payload.reservations) {
165	      if (row.id && (await db.reservations.get(row.id))) {
166	        skipped += 1;
