182	        skipped += 1;
183	      } else {
184	        await db.orders.add(row as never);
185	        inserted += 1;
186	      }
187	    }
188	    for (const row of payload.reservationsCold) {
189	      if (row.id && (await db.reservations_cold.get(row.id))) {
190	        skipped += 1;
191	      } else {
192	        await db.reservations_cold.add(row as never);
193	        inserted += 1;
194	      }
195	    }
196	    for (const row of payload.sessionsCold) {
197	      if (row.id && (await db.sessions_cold.get(row.id))) {
198	        skipped += 1;
199	      } else {
200	        await db.sessions_cold.add(row as never);
201	        inserted += 1;
202	      }
