15	function toDataUrl(payload: string): string {
16	  if (typeof document === 'undefined') {
17	    return `data:text/plain;base64,${btoa(payload)}`;
18	  }
19	
20	  const canvas = document.createElement('canvas');
21	  canvas.width = 220;
22	  canvas.height = 220;
23	  const context = canvas.getContext('2d');
24	  if (!context) {
25	    return `data:text/plain;base64,${btoa(payload)}`;
26	  }
27	
28	  context.fillStyle = '#ffffff';
29	  context.fillRect(0, 0, 220, 220);
30	  context.fillStyle = '#111827';
31	  context.font = '12px monospace';
32	  context.fillText('ChargeBay QR', 16, 30);
33	  const chunks = payload.match(/.{1,24}/g) ?? [payload];
34	  chunks.slice(0, 10).forEach((line, index) => {
35	    context.fillText(line, 16, 55 + index * 14);
36	  });
37	
38	  return canvas.toDataURL('image/png');
39	}
