124	async function runWeeklyIfDue(siteId: number, actor: User): Promise<boolean> {
125	  const key = `cb_quality_lastRun_${siteId}`;
126	  const now = Date.now();
127	  const lastRun = Number(localStorage.getItem(key) ?? 0);
128	  if (now - lastRun <= 7 * 24 * 60 * 60 * 1000) {
129	    return false;
130	  }
131	
132	  await runReport(siteId, actor);
133	  localStorage.setItem(key, String(now));
134	  return true;
135	}
