    // Provenance: order points back to its source batch
    expect(orders[0].importBatchId).toBe(batch.id);
  });

  it('ImportBatch → ImportRow → Reservation → billing lineage is traceable', async () => {
    const { user, key } = await setupForImport();
    const csv = [
      'stationId,connectorId,customerName,customerPlate,scheduledStart,scheduledEnd',
      'ST-01,C1,Carol Smith,PLATE02,04/01/2026 12:00,04/01/2026 13:00'
    ].join('\n');
    const file = new File([csv], 'reservations.csv', { type: 'text/csv' });
    const fieldMap = importService.autoMapFields(
      ['stationId', 'connectorId', 'customerName', 'customerPlate', 'scheduledStart', 'scheduledEnd'],
      'reservations'
    );

    const batch = await importService.startImport(file, 'reservations', fieldMap, user, key);
    const batchId = batch.id as number;

    // Step 1: ImportBatch exists
    const storedBatch = await db.importBatches.get(batchId);
    expect(storedBatch).toBeTruthy();

    // Step 2: ImportRow references the batch (raw data)
    const rows = await db.importRows.where('batchId').equals(batchId).toArray();
    expect(rows.length).toBe(1);
    expect(rows[0].rawData).toBeTruthy();
    expect(rows[0].cleanedData).toBeTruthy();
    expect(rows[0].status).toBe('Imported');

    // Step 3: Reservation references the batch (aggregated lineage)
    const reservation = await db.reservations
      .filter((r) => r.importBatchId === batchId)
      .first();
    expect(reservation).toBeTruthy();
    expect(reservation!.importBatchId).toBe(batchId);
    expect(reservation!.importRowId).toBe(rows[0].rowIndex);
  });
});
"}

