22	function overlaps(aStart: number, aEnd: number, bStart: number, bEnd: number): boolean {
23	  return aStart < bEnd && bStart < aEnd;
24	}
25	
26	export class BayConflictError extends Error {
27	  code = 'RES_BAY_CONFLICT' as const;
28	
29	  constructor() {
30	    super('RES_BAY_CONFLICT');
31	  }
32	}
33	
34	export class TempLeaveLimitError extends Error {
35	  code = 'TEMPLEAVE_LIMIT_REACHED' as const;
36	
37	  constructor() {
38	    super('TEMPLEAVE_LIMIT_REACHED');
39	  }
40	}
