42	async function createReservation(
43	  data: CreateReservationInput,
44	  actor: User,
45	  encryptionKey: CryptoKey
46	): Promise<Reservation> {
47	  assertCanMutate(actor);
48	  assertSiteScope(actor, data.siteId);
49	  const now = Date.now();
50	  if (data.scheduledStart >= data.scheduledEnd || data.scheduledStart <= now) {
51	    throw new Error('RES_INVALID_TIME_WINDOW');
52	  }
53	
54	  const existing = await db.reservations.where('operationId').equals(data.operationId).first();
55	  if (existing) {
56	    return existing;
57	  }
58	
59	  const activeReservations = await db.reservations
60	    .where('bayId')
61	    .equals(data.bayId)
62	    .filter((item) => ['Scheduled', 'CheckedIn', 'Active'].includes(item.status))
63	    .toArray();
64	
65	  const hasConflict = activeReservations.some((item) =>
66	    overlaps(data.scheduledStart, data.scheduledEnd, item.scheduledStart, item.scheduledEnd)
67	  );
68	  if (hasConflict) {
69	    throw new BayConflictError();
70	  }
71	
72	  const site = await db.sites.get(data.siteId);
73	  const qrPayload = qrService.encodePayload({
74	    reservationId: 0,
75	    operationId: data.operationId,
76	    siteCode: site?.siteCode ?? 'UNKNOWN'
77	  });
78	  const config = siteConfigService.getSiteConfig(data.siteId);
79	
80	  const reservation: Reservation = {
81	    operationId: data.operationId,
82	    bayId: data.bayId,
83	    siteId: data.siteId,
84	    userId: data.userId,
85	    customerName: await cryptoService.encryptField(data.customerName, encryptionKey),
86	    customerPlate: await cryptoService.encryptField(data.customerPlate, encryptionKey),
87	    scheduledStart: data.scheduledStart,
88	    scheduledEnd: data.scheduledEnd,
89	    status: 'Scheduled',
90	    qrCode: qrPayload,
91	    noShowDeadline: data.scheduledStart + config.noShowGraceMinutes * 60_000,
92	    version: 1
93	  };
94	
95	  const reservationId = await db.reservations.add(reservation);
96	  await db.bays.update(data.bayId, { status: 'Reserved' });
97	  await auditService.log(actor, 'RESERVATION_CREATED', 'Reservation', reservationId, {
98	    bayId: data.bayId,
99	    scheduledStart: data.scheduledStart
100	  });
101	
102	  const created = await db.reservations.get(reservationId);
103	  return created as Reservation;
104	}
