106	async function confirmArrival(
107	  reservationId: number,
108	  method: 'manual' | 'qr',
109	  actor: User,
110	  qrPayload?: string
111	): Promise<ChargingSession> {
112	  assertCanMutate(actor);
113	  const reservation = await db.reservations.get(reservationId);
114	  if (!reservation || reservation.status !== 'Scheduled') {
115	    throw new Error('RES_CONFIRM_INVALID_STATE');
116	  }
117	  assertSiteScope(actor, reservation.siteId);
118	
119	  if (method === 'qr') {
120	    if (!qrPayload) {
121	      throw new Error('RES_QR_MISSING');
122	    }
123	    const parsed = qrService.parsePayload(qrPayload);
124	    if (parsed.operationId !== reservation.operationId) {
125	      throw new Error('RES_QR_MISMATCH');
126	    }
127	  }
128	
129	  const now = Date.now();
130	  await db.reservations.update(reservationId, {
131	    status: 'CheckedIn',
132	    confirmedArrivalAt: now,
133	    confirmedBy: actor.id,
134	    version: reservation.version + 1
135	  });
136	  await db.bays.update(reservation.bayId, { status: 'Occupied' });
137	
138	  const session: ChargingSession = {
139	    reservationId,
140	    bayId: reservation.bayId,
141	    siteId: reservation.siteId,
142	    startedAt: now,
143	    status: 'Active',
144	    heartbeatAt: now,
145	    tempLeaveCount: 0,
146	    version: 1
147	  };
148	  const sessionId = await db.sessions_charging.add(session);
149	
150	  await db.reservations.update(reservationId, { status: 'Active' });
151	  await auditService.log(actor, 'ARRIVAL_CONFIRMED', 'Reservation', reservationId, {
152	    method,
153	    sessionId
154	  });
155	
156	  const created = await db.sessions_charging.get(sessionId);
157	  return created as ChargingSession;
158	}
