160	async function autoProcessNoShows(actor?: User): Promise<void> {
161	  if (actor) {
162	    assertCanMutate(actor);
163	  }
164	  const now = Date.now();
165	  const due = await db.reservations
166	    .where('status')
167	    .equals('Scheduled')
168	    .filter((item) => item.noShowDeadline <= now)
169	    .toArray();
170	
171	  for (const reservation of due) {
172	    await db.reservations.update(reservation.id as number, {
173	      status: 'NoShow',
174	      version: reservation.version + 1
175	    });
176	    await db.bays.update(reservation.bayId, { status: 'Available' });
