      month: '2-digit', day: '2-digit', year: 'numeric',
      hour: '2-digit', minute: '2-digit', hour12: false
    }).replace(',', '');

    // Use reservationService directly to guarantee a valid scheduledStart
    const reservation = await reservationService.createReservation(
      {
        operationId: crypto.randomUUID(),
        bayId: (await db.bays.toCollection().first())!.id as number,
        siteId: (await db.sites.toCollection().first())!.id as number,
        userId: user.id as number,
        customerName: 'Provenance Driver',
        customerPlate: 'PROV01',
        scheduledStart: start,
        scheduledEnd: end
      },
      user,
      key
    );

    // Manually tag the reservation with a fake importBatchId to simulate import
    const batchId = await db.importBatches.add({
      siteId: user.siteId as number,
      type: 'reservations',
      status: 'Complete',
      createdAt: Date.now(),
      dedupeHash: 'prov-hash',
      totalRows: 1,
      validRows: 1,
      invalidRows: 0,
      duplicateRows: 0
    });
    await db.reservations.update(reservation.id as number, { importBatchId: batchId });
    const tagged = (await db.reservations.get(reservation.id as number))!;

    // Confirm arrival: session should inherit importBatchId
    const session = await reservationService.confirmArrival(tagged.id as number, 'manual', user);
    expect(session.importBatchId).toBe(batchId);

    // Complete the session so an order can be generated
    await db.sessions_charging.update(session.id as number, {
      status: 'Completed',
      endedAt: Date.now()
    });
    await sessionService.completeSession(session.id as number, user);

    // Order should inherit importBatchId from session
    const order = await db.orders.where('sessionId').equals(session.id as number).first();
    expect(order).toBeTruthy();
    expect(order!.importBatchId).toBe(batchId);

    // Reconciliation status starts as Unreconciled; can be set to Matched
    expect(order!.reconciliationStatus).toBe('Unreconciled');
    await orderService.setReconciliationStatus(order!.id as number, 'Matched', user);
    const reconciled = await db.orders.get(order!.id as number);
    expect(reconciled!.reconciliationStatus).toBe('Matched');

    // Full chain: importBatchId links Order back to ImportBatch
    const linkedBatch = await db.importBatches.get(order!.importBatchId as number);
    expect(linkedBatch!.id).toBe(batchId);
    expect(linkedBatch!.type).toBe('reservations');
  });
});"}

