1	import { db } from '../db/db';
2	import type { User } from '../types';
3	import { auditService } from './auditService';
4	import { orderService } from './orderService';
5	import { assertCanMutate, assertSiteScope } from './rbacService';
6	
7	function assertManagerOrAdmin(actor: User) {
8	  if (actor.role !== 'SystemAdministrator' && actor.role !== 'SiteManager') {
9	    throw new Error('RBAC_SCOPE_VIOLATION');
10	  }
11	}
12	
13	async function completeSession(sessionId: number, actor: User): Promise<void> {
14	  assertCanMutate(actor);
15	  const session = await db.sessions_charging.get(sessionId);
16	  if (!session || session.status !== 'Active') {
17	    throw new Error('SESSION_INVALID_STATE');
18	  }
19	  assertSiteScope(actor, session.siteId);
20	
21	  const now = Date.now();
22	  await db.sessions_charging.update(sessionId, {
23	    status: 'Completed',
24	    endedAt: now,
25	    version: session.version + 1
26	  });
27	  await db.bays.update(session.bayId, { status: 'Available' });
28	  await db.reservations.update(session.reservationId, { status: 'Completed' });
29	  await orderService.generateOrder(sessionId, actor);
30	  await auditService.log(actor, 'SESSION_COMPLETED', 'ChargingSession', sessionId);
31	}
32	
33	async function resolveAnomaly(
34	  sessionId: number,
35	  resolution: 'complete' | 'cancel',
36	  reason: string,
37	  actor: User
38	): Promise<void> {
39	  assertManagerOrAdmin(actor);
40	  if (reason.trim().length < 10) {
41	    throw new Error('ANOMALY_REASON_TOO_SHORT');
42	  }
43	
44	  const session = await db.sessions_charging.get(sessionId);
45	  if (!session || session.status !== 'Anomaly') {
46	    throw new Error('SESSION_INVALID_STATE');
47	  }
48	  assertSiteScope(actor, session.siteId);
49	
50	  if (resolution === 'complete') {
51	    await db.sessions_charging.update(sessionId, { status: 'Active' });
52	    await completeSession(sessionId, actor);
53	  } else {
54	    const now = Date.now();
55	    await db.sessions_charging.update(sessionId, {
56	      status: 'Completed',
57	      endedAt: now,
58	      anomalyReason: `${session.anomalyReason ?? ''} | cancelled: ${reason}`,
59	      version: session.version + 1
60	    });
61	    await db.reservations.update(session.reservationId, { status: 'Cancelled' });
62	    await db.bays.update(session.bayId, { status: 'Available' });
63	  }
64	
65	  await auditService.log(actor, 'ANOMALY_RESOLVED', 'ChargingSession', sessionId, {
66	    resolution,
67	    reason
68	  });
69	}
70	
71	export const sessionService = {
72	  completeSession,
73	  resolveAnomaly
74	};
75	

