1	import * as XLSX from 'xlsx';
2	import { db } from '../db/db';
3	import type { ImportBatch, ImportRow, User } from '../types';
4	import { auditService } from './auditService';
5	import { cryptoService } from './cryptoService';
6	import { notificationService } from './notificationService';
7	
8	export type ImportType = 'reservations' | 'orders' | 'sessions';
9	export type FieldMap = Record<string, string>;
10	
11	const REQUIRED_FIELDS: Record<ImportType, string[]> = {
12	  reservations: [
13	    'stationId',
14	    'connectorId',
15	    'customerName',
16	    'customerPlate',
17	    'scheduledStart',
18	    'scheduledEnd'
19	  ],
20	  orders: [
21	    'orderNumber',
22	    'sessionId',
23	    'durationMinutes',
24	    'ratePerMinute',
25	    'adjustmentAmount',
26	    'adjustmentReason',
27	    'invoiceNotes'
28	  ],
29	  sessions: ['reservationId', 'startedAt']
30	};
31	
32	const TEMPLATE_ROWS: Record<ImportType, { headers: string[]; sample: string[] }> = {
33	  reservations: {
34	    headers: [
35	      'stationId',
36	      'connectorId',
37	      'customerName',
38	      'customerPlate',
39	      'scheduledStart',
40	      'scheduledEnd'
41	    ],
42	    sample: ['ST-01', 'C1', 'Alex Doe', 'ABC123', '04/01/2026 09:30', '04/01/2026 11:00']
43	  },
44	  orders: {
45	    headers: [
46	      'orderNumber',
47	      'sessionId',
48	      'durationMinutes',
49	      'ratePerMinute',
50	      'adjustmentAmount',
51	      'adjustmentReason',
52	      'invoiceNotes'
53	    ],
54	    sample: ['CB-SITE-001-20260401-0001', '100', '90', '0.5', '0', '', 'Imported invoice note']
55	  },
56	  sessions: {
57	    headers: ['reservationId', 'startedAt'],
58	    sample: ['100', '04/01/2026 09:30']
59	  }
60	};
