62	function parseCsv(csv: string): { headers: string[]; rows: Record<string, string>[] } {
63	  const lines = csv
64	    .split(/\r?\n/)
65	    .map((line) => line.trim())
66	    .filter(Boolean);
67	  if (lines.length === 0) {
68	    return { headers: [], rows: [] };
69	  }
70	  const headers = lines[0].split(',').map((entry) => entry.trim());
71	  const rows = lines.slice(1).map((line) => {
72	    const cells = line.split(',');
73	    const row: Record<string, string> = {};
74	    headers.forEach((header, index) => {
75	      row[header] = (cells[index] ?? '').trim();
76	    });
77	    return row;
78	  });
79	
80	  return { headers, rows };
81	}
82	
83	function parseDate(value: string): number | null {
84	  const match = value.match(/^(\d{2})\/(\d{2})\/(\d{4})\s(\d{2}):(\d{2})$/);
85	  if (!match) {
86	    return null;
87	  }
88	  const [, mm, dd, yyyy, hh, min] = match;
89	  const date = new Date(Number(yyyy), Number(mm) - 1, Number(dd), Number(hh), Number(min));
90	  if (Number.isNaN(date.getTime())) {
91	    return null;
92	  }
93	  return date.getTime();
94	}
95	
96	async function sha256(text: string): Promise<string> {
97	  const buffer = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(text));
98	  return [...new Uint8Array(buffer)].map((b) => b.toString(16).padStart(2, '0')).join('');
99	}
100	
101	async function parseFile(file: File): Promise<{ headers: string[]; rows: Record<string, string>[]; raw: string }> {
102	  const readAsText =
103	    'text' in file
104	      ? async () => (await (file as unknown as { text: () => Promise<string> }).text())
105	      : async () =>
106	          await new Promise<string>((resolve, reject) => {
107	            const reader = new FileReader();
108	            reader.onload = () => resolve(String(reader.result ?? ''));
109	            reader.onerror = () => reject(reader.error);
110	            reader.readAsText(file);
111	          });
112	
113	  const readAsArrayBuffer =
114	    'arrayBuffer' in file
115	      ? async () =>
116	          await (file as unknown as { arrayBuffer: () => Promise<ArrayBuffer> }).arrayBuffer()
117	      : async () =>
118	          await new Promise<ArrayBuffer>((resolve, reject) => {
119	            const reader = new FileReader();
120	            reader.onload = () => resolve(reader.result as ArrayBuffer);
121	            reader.onerror = () => reject(reader.error);
122	            reader.readAsArrayBuffer(file);
123	          });
124	
125	  if (file.name.toLowerCase().endsWith('.xlsx')) {
126	    const bytes = await readAsArrayBuffer();
127	    const workbook = XLSX.read(bytes, { type: 'array' });
128	    const sheet = workbook.Sheets[workbook.SheetNames[0]];
129	    const matrix = XLSX.utils.sheet_to_json<(string | number)[]>(sheet, { header: 1 });
130	    const [headersRow = [], ...body] = matrix;
131	    const headers = headersRow.map((cell) => String(cell).trim());
132	    const rows = body.map((cells) => {
133	      const row: Record<string, string> = {};
134	      headers.forEach((header, index) => {
135	        row[header] = String(cells[index] ?? '').trim();
136	      });
137	      return row;
138	    });
139	    return { headers, rows, raw: JSON.stringify(matrix) };
140	  }
141	
142	  const text = await readAsText();
143	  const parsed = parseCsv(text);
144	  return { ...parsed, raw: text };
145	}
146	
147	function applyFieldMap(row: Record<string, string>, fieldMap: FieldMap): Record<string, string> {
148	  const mapped: Record<string, string> = {};
149	  Object.entries(fieldMap).forEach(([source, target]) => {
150	    if (target) {
151	      mapped[target] = row[source] ?? '';
152	    }
153	  });
154	  return mapped;
155	}
156	
157	async function validateRows(
158	  rows: Record<string, string>[],
159	  type: ImportType,
160	  actor: User
161	): Promise<{ importRows: ImportRow[]; invalidCount: number; validCount: number }> {
162	  const output: ImportRow[] = [];
163	  let invalidCount = 0;
164	  let validCount = 0;
165	
166	  for (let index = 0; index < rows.length; index += 1) {
167	    const row = rows[index];
168	    let errorCode: string | undefined;
169	
170	    for (const field of REQUIRED_FIELDS[type]) {
171	      if (!row[field]) {
172	        errorCode = 'IMPORT_REQUIRED_FIELD_MISSING';
173	      }
174	    }
175	
176	    if (!errorCode && type === 'reservations') {
177	      const start = parseDate(row.scheduledStart);
178	      const end = parseDate(row.scheduledEnd);
179	      if (!start || !end) {
180	        errorCode = 'IMPORT_DATE_FORMAT_INVALID';
181	      } else if (start >= end) {
182	        errorCode = 'IMPORT_DATE_RANGE_INVALID';
183	      } else {
184	        const bay = await db.bays
185	          .where('siteId')
186	          .equals(actor.siteId as number)
187	          .filter((b) => b.stationId === row.stationId && b.connectorId === row.connectorId)
188	          .first();
189	        if (!bay) {
190	          errorCode = 'IMPORT_BAY_NOT_FOUND';
191	        }
192	      }
193	    }
194	
195	    if (!errorCode && type === 'orders') {
196	      const duration = Number(row.durationMinutes);
197	      const rate = Number(row.ratePerMinute);
198	      const adjustment = Number(row.adjustmentAmount);
199	      if (!(duration > 0)) {
200	        errorCode = 'IMPORT_DURATION_INVALID';
201	      } else if (!(rate > 0) || Number(rate.toFixed(2)) !== rate) {
202	        errorCode = 'IMPORT_RATE_INVALID';
203	      } else if (Number.isNaN(adjustment)) {
204	        errorCode = 'IMPORT_ADJUSTMENT_INVALID';
205	      }
206	    }
207	
208	    output.push({
209	      batchId: 0,
210	      rowIndex: index + 1,
211	      status: errorCode ? 'Invalid' : 'Valid',
212	      rawData: JSON.stringify(rows[index]),
213	      cleanedData: JSON.stringify(row),
214	      errorCode
215	    });
216	
217	    if (errorCode) {
218	      invalidCount += 1;
219	    } else {
220	      validCount += 1;
221	    }
222	  }
223	
224	  return { importRows: output, invalidCount, validCount };
225	}
226	
227	function autoMapFields(headers: string[], type: ImportType): FieldMap {
228	  const required = REQUIRED_FIELDS[type];
229	  const lowerMap = new Map(required.map((field) => [field.toLowerCase(), field]));
230	  const map: FieldMap = {};
231	  headers.forEach((header) => {
232	    const target = lowerMap.get(header.toLowerCase());
233	    map[header] = target ?? '';
234	  });
235	  return map;
236	}
237	
238	function generateCsv(rows: string[][]): string {
239	  return rows.map((line) => line.join(',')).join('\n');
240	}
241	
242	function downloadTemplate(type: ImportType): void {
243	  const def = TEMPLATE_ROWS[type];
244	  const csv = generateCsv([def.headers, def.sample]);
245	  const blob = new Blob([csv], { type: 'text/csv' });
246	  const url = URL.createObjectURL(blob);
247	  const a = document.createElement('a');
248	  a.href = url;
249	  a.download = `${type}_template.csv`;
250	  a.click();
251	  URL.revokeObjectURL(url);
252	}
253	
254	async function validateFile(
255	  file: File,
256	  type: ImportType,
257	  fieldMap: FieldMap,
258	  actor: User
259	): Promise<{ totalRows: number; validRows: number; invalidRows: number; rows: ImportRow[]; headers: string[] }> {
260	  const parsed = await parseFile(file);
261	  const mappedRows = parsed.rows.map((row) => applyFieldMap(row, fieldMap));
262	  const validated = await validateRows(mappedRows, type, actor);
263	  return {
264	    totalRows: mappedRows.length,
265	    validRows: validated.validCount,
266	    invalidRows: validated.invalidCount,
267	    rows: validated.importRows,
268	    headers: parsed.headers
269	  };
270	}
271	
272	async function startImport(
273	  file: File,
274	  type: ImportType,
275	  fieldMap: FieldMap,
276	  actor: User,
277	  encryptionKey?: CryptoKey
278	): Promise<ImportBatch> {
279	  if (type !== 'sessions' && !encryptionKey) {
280	    throw new Error('IMPORT_ENCRYPTION_KEY_REQUIRED');
281	  }
282	
283	  const parsed = await parseFile(file);
284	  const dedupeHash = await sha256(parsed.raw);
285	
286	  const existingBatch = await db.importBatches
287	    .where('siteId')
288	    .equals(actor.siteId as number)
289	    .filter((b) => b.dedupeHash === dedupeHash)
290	    .first();
291	  if (existingBatch) {
292	    throw new Error('IMPORT_DUPLICATE_FILE');
293	  }
294	
295	  const batchId = await db.importBatches.add({
296	    siteId: actor.siteId as number,
297	    type,
298	    status: 'Validating',
299	    createdAt: Date.now(),
300	    dedupeHash
301	  });
302	
303	  const mappedRows = parsed.rows.map((row) => applyFieldMap(row, fieldMap));
304	  const validation = await validateRows(mappedRows, type, actor);
305	  const validationRows = validation.importRows.map((row) => ({ ...row, batchId }));
306	  await db.importRows.bulkAdd(validationRows);
307	
308	  if (validation.invalidCount > 0) {
309	    await db.importBatches.update(batchId, {
310	      status: 'Failed',
311	      totalRows: mappedRows.length,
312	      validRows: validation.validCount,
313	      invalidRows: validation.invalidCount,
314	      duplicateRows: 0,
315	      errorSummary: `${validation.invalidCount} invalid rows`
316	    });
317	    await notificationService.send(actor.id as number, 'IMPORT_FAILED', {
318	      batchId: String(batchId),
319	      reason: `${validation.invalidCount} validation errors`
320	    });
321	    return (await db.importBatches.get(batchId)) as ImportBatch;
322	  }
323	
324	  // Pre-encrypt sensitive fields outside the Dexie transaction
325	  // (WebCrypto operations break IndexedDB transaction scope)
326	  const encryptedRows: Array<{ encName?: string; encPlate?: string; encNotes?: string }> = [];
327	  if (type === 'reservations' || type === 'orders') {
328	    for (const row of mappedRows) {
329	      if (type === 'reservations') {
330	        encryptedRows.push({
331	          encName: await cryptoService.encryptField(row.customerName, encryptionKey!),
332	          encPlate: await cryptoService.encryptField(row.customerPlate, encryptionKey!)
333	        });
334	      } else {
335	        encryptedRows.push({
336	          encNotes: await cryptoService.encryptField(row.invoiceNotes, encryptionKey!)
337	        });
338	      }
339	    }
340	  }
341	
342	  let duplicateRows = 0;
343	  await db.transaction(
344	    'rw',
345	    db.reservations,
346	    db.orders,
347	    db.sessions_charging,
348	    db.bays,
349	    db.importRows,
350	    async () => {
351	      for (let index = 0; index < mappedRows.length; index += 1) {
352	        const row = mappedRows[index];
353	        let isDuplicate = false;
354	
355	        if (type === 'reservations') {
356	          const start = parseDate(row.scheduledStart) as number;
357	          const bay = await db.bays
358	            .where('siteId')
359	            .equals(actor.siteId as number)
360	            .filter((b) => b.stationId === row.stationId && b.connectorId === row.connectorId)
361	            .first();
362	
363	          const dup = await db.reservations
364	            .where('siteId')
365	            .equals(actor.siteId as number)
366	            .filter((r) => r.bayId === bay?.id && r.scheduledStart === start)
367	            .first();
368	          if (dup) {
369	            isDuplicate = true;
370	          } else {
371	            const encName = encryptedRows[index]!.encName!;
372	            const encPlate = encryptedRows[index]!.encPlate!;
373	            await db.reservations.add({
374	              operationId: crypto.randomUUID(),
375	              bayId: bay?.id as number,
376	              siteId: actor.siteId as number,
377	              userId: actor.id as number,
378	              customerName: encName,
379	              customerPlate: encPlate,
380	              scheduledStart: start,
381	              scheduledEnd: parseDate(row.scheduledEnd) as number,
382	              status: 'Scheduled',
383	              noShowDeadline: start + 10 * 60_000,
384	              version: 1,
385	              importBatchId: batchId,
386	              importRowId: index + 1
387	            });
388	          }
389	        }
390	
391	        if (type === 'orders') {
392	          const dup = await db.orders
393	            .where('siteId')
394	            .equals(actor.siteId as number)
395	            .filter((o) => o.orderNumber === row.orderNumber)
396	            .first();
397	          if (dup) {
398	            isDuplicate = true;
399	          } else {
400	            const duration = Number(row.durationMinutes);
401	            const rate = Number(row.ratePerMinute);
402	            const adjustment = Number(row.adjustmentAmount);
403	            const subtotal = Number((duration * rate).toFixed(2));
404	            const encNotes = encryptedRows[index]!.encNotes!;
405	            await db.orders.add({
406	              operationId: crypto.randomUUID(),
407	              sessionId: Number(row.sessionId),
408	              siteId: actor.siteId as number,
409	              orderNumber: row.orderNumber,
410	              status: 'Draft',
411	              billingType: 'Standard',
412	              durationMinutes: duration,
413	              ratePerMinute: rate,
414	              subtotal,
415	              adjustmentAmount: adjustment,
416	              adjustmentReason: row.adjustmentReason,
417	              totalAmount: Number((subtotal + adjustment).toFixed(2)),
418	              invoiceNotes: encNotes,
419	              reconciliationStatus: 'Unreconciled',
420	              version: 1,
421	              importBatchId: batchId
422	            });
423	          }
424	        }
425	
426	        if (type === 'sessions') {
427	          const startedAt = parseDate(row.startedAt);
428	          const dup = await db.sessions_charging
429	            .where('reservationId')
430	            .equals(Number(row.reservationId))
431	            .filter((s) => s.startedAt === startedAt)
432	            .first();
433	          if (dup) {
