42	async function createReservation(
43	  data: CreateReservationInput,
44	  actor: User,
45	  encryptionKey: CryptoKey
46	): Promise<Reservation> {
47	  assertCanMutate(actor);
48	  assertSiteScope(actor, data.siteId);
49	  const now = Date.now();
50	  if (data.scheduledStart >= data.scheduledEnd || data.scheduledStart <= now) {
51	    throw new Error('RES_INVALID_TIME_WINDOW');
52	  }
53	
54	  const existing = await db.reservations.where('operationId').equals(data.operationId).first();
55	  if (existing) {
56	    return existing;
57	  }
58	
59	  const activeReservations = await db.reservations
60	    .where('bayId')
61	    .equals(data.bayId)
62	    .filter((item) => ['Scheduled', 'CheckedIn', 'Active'].includes(item.status))
63	    .toArray();
64	
65	  const hasConflict = activeReservations.some((item) =>
66	    overlaps(data.scheduledStart, data.scheduledEnd, item.scheduledStart, item.scheduledEnd)
67	  );
68	  if (hasConflict) {
69	    throw new BayConflictError();
70	  }
71	
72	  const site = await db.sites.get(data.siteId);
73	  const config = siteConfigService.getSiteConfig(data.siteId);
74	
75	  // Add the reservation first so we obtain the real persisted primary key.
76	  // The QR payload must embed the real reservationId, so it is generated and
77	  // written back after the initial insert.
78	  const reservationId = await db.reservations.add({
79	    operationId: data.operationId,
80	    bayId: data.bayId,
81	    siteId: data.siteId,
82	    userId: data.userId,
83	    customerName: await cryptoService.encryptField(data.customerName, encryptionKey),
84	    customerPlate: await cryptoService.encryptField(data.customerPlate, encryptionKey),
85	    scheduledStart: data.scheduledStart,
86	    scheduledEnd: data.scheduledEnd,
87	    status: 'Scheduled',
88	    noShowDeadline: data.scheduledStart + config.noShowGraceMinutes * 60_000,
89	    version: 1
90	  });
91	
92	  // Bind QR to the real persisted reservation identity.
93	  const qrPayload = qrService.encodePayload({
94	    reservationId: reservationId as number,
95	    operationId: data.operationId,
96	    siteCode: site?.siteCode ?? 'UNKNOWN'
97	  });
98	  await db.reservations.update(reservationId, { qrCode: qrPayload });
99	
100	  await db.bays.update(data.bayId, { status: 'Reserved' });
101	  await auditService.log(actor, 'RESERVATION_CREATED', 'Reservation', reservationId, {
102	    bayId: data.bayId,
103	    scheduledStart: data.scheduledStart
104	  });
105	
106	  const created = await db.reservations.get(reservationId);
107	  return created as Reservation;
108	}
