110	async function confirmArrival(
111	  reservationId: number,
112	  method: 'manual' | 'qr',
113	  actor: User,
114	  qrPayload?: string
115	): Promise<ChargingSession> {
116	  assertCanMutate(actor);
117	  const reservation = await db.reservations.get(reservationId);
118	  if (!reservation || reservation.status !== 'Scheduled') {
119	    throw new Error('RES_CONFIRM_INVALID_STATE');
120	  }
121	  assertSiteScope(actor, reservation.siteId);
122	
123	  if (method === 'qr') {
124	    if (!qrPayload) {
125	      throw new Error('RES_QR_MISSING');
126	    }
127	    const parsed = qrService.parsePayload(qrPayload);
128	    const site = await db.sites.get(reservation.siteId);
129	    if (
130	      parsed.reservationId !== reservation.id ||
131	      parsed.operationId !== reservation.operationId ||
132	      parsed.siteCode !== (site?.siteCode ?? 'UNKNOWN')
133	    ) {
134	      throw new Error('RES_QR_MISMATCH');
135	    }
136	  }
137	
138	  const now = Date.now();
139	  await db.reservations.update(reservationId, {
140	    status: 'CheckedIn',
141	    confirmedArrivalAt: now,
142	    confirmedBy: actor.id,
143	    version: reservation.version + 1
144	  });
145	  await db.bays.update(reservation.bayId, { status: 'Occupied' });
146	
147	  const session: ChargingSession = {
148	    reservationId,
149	    bayId: reservation.bayId,
150	    siteId: reservation.siteId,
151	    startedAt: now,
152	    status: 'Active',
153	    heartbeatAt: now,
154	    tempLeaveCount: 0,
155	    version: 1,
156	    ...(reservation.importBatchId !== undefined ? { importBatchId: reservation.importBatchId } : {})
157	  };
158	  const sessionId = await db.sessions_charging.add(session);
159	
160	  await db.reservations.update(reservationId, { status: 'Active' });
161	  await auditService.log(actor, 'ARRIVAL_CONFIRMED', 'Reservation', reservationId, {
162	    method,
163	    sessionId
164	  });
165	
166	  const created = await db.sessions_charging.get(sessionId);
167	  return created as ChargingSession;
168	}
