26	async function generateOrder(sessionId: number, actor: User, encryptionKey?: CryptoKey): Promise<Order> {
27	  assertCanMutate(actor);
28	  const existing = await db.orders.where('sessionId').equals(sessionId).filter((o) => o.status !== 'Voided').first();
29	  if (existing) {
30	    return existing;
31	  }
32	
33	  const session = await db.sessions_charging.get(sessionId);
34	  if (!session || session.status !== 'Completed' || !session.endedAt) {
35	    throw new Error('ORDER_SESSION_NOT_COMPLETED');
36	  }
37	  assertSiteScope(actor, session.siteId);
38	
39	  const config = siteConfigService.getSiteConfig(session.siteId);
40	  const site = await db.sites.get(session.siteId);
41	  const minutes = Math.max(1, Math.ceil((session.endedAt - session.startedAt) / 60_000));
42	  const subtotal = Number((minutes * config.ratePerMinute).toFixed(2));
43	  const total = subtotal;
44	  const dayKey = dateKey(session.endedAt);
45	  const todayOrders = await db.orders
46	    .where('siteId')
47	    .equals(session.siteId)
48	    .filter((order) => order.orderNumber.includes(dayKey))
49	    .count();
50	  const seq = String(todayOrders + 1).padStart(4, '0');
51	  const orderNumber = `CB-${site?.siteCode ?? 'SITE'}-${dayKey}-${seq}`;
52	  const operationId = `order-${sessionId}`;
53	
54	  const idempotent = (await db.orders.toArray()).find((order) => order.operationId === operationId);
55	  if (idempotent) {
56	    return idempotent;
57	  }
58	
59	  const encryptedNotes = encryptionKey
60	    ? await cryptoService.encryptField('', encryptionKey)
61	    : btoa('');
62	
63	  const orderId = await db.orders.add({
64	    operationId,
65	    sessionId,
66	    siteId: session.siteId,
67	    createdAt: Date.now(),
68	    orderNumber,
69	    status: 'Draft',
70	    billingType: 'Standard',
71	    durationMinutes: minutes,
72	    ratePerMinute: config.ratePerMinute,
73	    subtotal,
74	    adjustmentAmount: 0,
75	    totalAmount: total,
76	    invoiceNotes: encryptedNotes,
77	    reconciliationStatus: 'Unreconciled',
78	    version: 1,
79	    ...(session.importBatchId !== undefined ? { importBatchId: session.importBatchId } : {})
80	  });
81	
82	  await auditService.log(actor, 'ORDER_GENERATED', 'Order', orderId, { sessionId, orderNumber });
83	  return (await db.orders.get(orderId)) as Order;
84	}
