161	  await auditService.log(actor, 'ORDER_PAID', 'Order', orderId);
162	}
163	
164	async function refundOrder(orderId: number, reason: string, actor: User): Promise<void> {
165	  assertApprover(actor);
166	  if (reason.trim().length < 5) {
167	    throw new Error('ORDER_REFUND_REASON_REQUIRED');
168	  }
169	  const order = await db.orders.get(orderId);
170	  if (!order) {
171	    throw new Error('ORDER_NOT_FOUND');
172	  }
173	  assertSiteScope(actor, order.siteId);
174	
175	  await db.orders.update(orderId, {
176	    status: 'Refunded',
177	    adjustmentReason: reason,
178	    version: order.version + 1
179	  });
180	  await notificationService.sendTemplateToSiteStaff(order.siteId, 'ORDER_REFUNDED', actor, {
181	    orderNumber: order.orderNumber,
182	    reason
183	  });
184	  await auditService.log(actor, 'ORDER_REFUNDED', 'Order', orderId, { reason });
185	}
186	
187	async function setReconciliationStatus(
188	  orderId: number,
189	  status: 'Matched' | 'Discrepancy',
190	  actor: User
191	): Promise<void> {
192	  if (actor.role !== 'SystemAdministrator' && actor.role !== 'SiteManager') {
193	    throw new Error('RBAC_SCOPE_VIOLATION');
194	  }
195	  const order = await db.orders.get(orderId);
196	  if (!order) {
197	    throw new Error('ORDER_NOT_FOUND');
198	  }
199	  assertSiteScope(actor, order.siteId);
200	
201	  await db.orders.update(orderId, { reconciliationStatus: status, version: order.version + 1 });
202	  await auditService.log(actor, 'ORDER_RECONCILIATION_UPDATED', 'Order', orderId, { status });
203	}
204	
205	async function bulkMarkPaid(orderIds: number[], actor: User): Promise<void> {
206	  const userId = actor.id as number;
207	  rateLimiter.check(userId, 'bulk_order_mark_paid', 200, 60_000, orderIds.length);
208	  rateLimiter.record(userId, 'bulk_order_mark_paid', orderIds.length);
209	
210	  for (const orderId of orderIds) {
211	    await markPaid(orderId, actor);
212	  }
213	}
