1	/**
2	 * Import provenance tests.
3	 * Verifies that imported records carry importBatchId/importRowId so the
4	 * raw → cleaned → billing lineage is traceable end-to-end through
5	 * ImportBatch → ImportRow → Reservation → ChargingSession → Order.
6	 */
7	import { beforeEach, describe, expect, it } from 'vitest';
8	import { db } from '../db/db';
9	import { cryptoService } from '../services/cryptoService';
10	import { importService } from '../services/importService';
11	import { orderService } from '../services/orderService';
12	import { reservationService } from '../services/reservationService';
13	import { sessionService } from '../services/sessionService';
14	import { siteConfigService } from '../services/siteConfigService';
15	
16	async function resetDb() {
17	  await db.delete();
18	  await db.open();
19	}
20	
21	async function setupForImport() {
22	  const siteId = await db.sites.add({ siteCode: 'SITE-001', name: 'Test Site' });
23	  await db.bays.add({ siteId, stationId: 'ST-01', connectorId: 'C1', label: 'Bay 1', status: 'Available' });
24	  const hash = await cryptoService.hashPassword('ChargeBay#Mgr01');
25	  const userId = await db.users.add({
26	    username: 'manager',
27	    passwordHash: hash.hash,
28	    salt: hash.salt,
29	    role: 'SiteManager',
30	    siteId,
31	    failedAttempts: 0
32	  });
33	  await siteConfigService.saveSiteConfig({
34	    siteId,
35	    tempLeaveMaxCount: 1,
36	    tempLeaveMaxMinutes: 15,
37	    anomalyHeartbeatTimeoutMin: 30,
38	    noShowGraceMinutes: 10,
39	    ratePerMinute: 0.5
40	  });
41	  const user = (await db.users.get(userId))!;
42	  const key = await cryptoService.deriveEncryptionKey('ChargeBay#Mgr01', user.salt);
43	  return { siteId, user, key };
44	}
45	
46	describe('Import provenance (raw → cleaned → billing lineage)', () => {
47	  beforeEach(resetDb);
48	
49	  it('imported reservation carries importBatchId linking back to the ImportBatch', async () => {
50	    const { user, key } = await setupForImport();
51	    const csv = [
52	      'stationId,connectorId,customerName,customerPlate,scheduledStart,scheduledEnd',
53	      'ST-01,C1,Alice Doe,PLATE01,04/01/2026 09:30,04/01/2026 11:00'
54	    ].join('\n');
55	    const file = new File([csv], 'reservations.csv', { type: 'text/csv' });
56	    const fieldMap = importService.autoMapFields(
57	      ['stationId', 'connectorId', 'customerName', 'customerPlate', 'scheduledStart', 'scheduledEnd'],
58	      'reservations'
59	    );
60	
61	    const batch = await importService.startImport(file, 'reservations', fieldMap, user, key);
62	    expect(batch.status).toBe('Complete');
63	
64	    const reservations = await db.reservations.toArray();
65	    expect(reservations.length).toBe(1);
66	
67	    // Provenance: reservation points back to its source batch
68	    expect(reservations[0].importBatchId).toBe(batch.id);
69	    expect(reservations[0].importRowId).toBe(1);
70	  });
71	
72	  it('imported order carries importBatchId linking back to the ImportBatch', async () => {
73	    const { user, key } = await setupForImport();
74	    const csv = [
75	      'orderNumber,sessionId,durationMinutes,ratePerMinute,adjustmentAmount,adjustmentReason,invoiceNotes',
76	      'CB-001,100,60,0.50,0,none,Test note'
77	    ].join('\n');
78	    const file = new File([csv], 'orders.csv', { type: 'text/csv' });
79	    const fieldMap = importService.autoMapFields(
80	      ['orderNumber', 'sessionId', 'durationMinutes', 'ratePerMinute', 'adjustmentAmount', 'adjustmentReason', 'invoiceNotes'],
81	      'orders'
82	    );
83	
84	    const batch = await importService.startImport(file, 'orders', fieldMap, user, key);
85	    expect(batch.status).toBe('Complete');
86	
87	    const orders = await db.orders.toArray();
88	    expect(orders.length).toBe(1);
89	
90	    // Provenance: order points back to its source batch
91	    expect(orders[0].importBatchId).toBe(batch.id);
92	  });
93	
94	  it('ImportBatch → ImportRow → Reservation → billing lineage is traceable', async () => {
95	    const { user, key } = await setupForImport();
96	    const csv = [
97	      'stationId,connectorId,customerName,customerPlate,scheduledStart,scheduledEnd',
98	      'ST-01,C1,Carol Smith,PLATE02,04/01/2026 12:00,04/01/2026 13:00'
99	    ].join('\n');
100	    const file = new File([csv], 'reservations.csv', { type: 'text/csv' });
101	    const fieldMap = importService.autoMapFields(
102	      ['stationId', 'connectorId', 'customerName', 'customerPlate', 'scheduledStart', 'scheduledEnd'],
103	      'reservations'
104	    );
105	
106	    const batch = await importService.startImport(file, 'reservations', fieldMap, user, key);
107	    const batchId = batch.id as number;
108	
109	    // Step 1: ImportBatch exists
110	    const storedBatch = await db.importBatches.get(batchId);
111	    expect(storedBatch).toBeTruthy();
112	
113	    // Step 2: ImportRow references the batch (raw data)
114	    const rows = await db.importRows.where('batchId').equals(batchId).toArray();
115	    expect(rows.length).toBe(1);
116	    expect(rows[0].rawData).toBeTruthy();
117	    expect(rows[0].cleanedData).toBeTruthy();
118	    expect(rows[0].status).toBe('Imported');
119	
120	    // Step 3: Reservation references the batch (aggregated lineage)
121	    const reservation = await db.reservations
122	      .filter((r) => r.importBatchId === batchId)
123	      .first();
124	    expect(reservation).toBeTruthy();
125	    expect(reservation!.importBatchId).toBe(batchId);
126	    expect(reservation!.importRowId).toBe(rows[0].rowIndex);
127	  });
128	
129	  it('Reservation import → confirmArrival → completeSession → Order: full provenance without record patching', async () => {
130	    const { user, key } = await setupForImport();
131	
132	    // Import a reservation via the real import flow — no manual DB patching.
133	    const csv = [
134	      'stationId,connectorId,customerName,customerPlate,scheduledStart,scheduledEnd',
135	      'ST-01,C1,Prov Driver,PROV01,04/01/2026 08:00,04/01/2026 09:00'
136	    ].join('\n');
137	    const file = new File([csv], 'prov_res.csv', { type: 'text/csv' });
138	    const fieldMap = importService.autoMapFields(
139	      ['stationId', 'connectorId', 'customerName', 'customerPlate', 'scheduledStart', 'scheduledEnd'],
140	      'reservations'
141	    );
142	    const batch = await importService.startImport(file, 'reservations', fieldMap, user, key);
143	    const batchId = batch.id as number;
144	    expect(batch.status).toBe('Complete');
145	
146	    // The reservation was created by the import with importBatchId set.
147	    const reservation = (await db.reservations.filter((r) => r.importBatchId === batchId).first())!;
148	    expect(reservation.importBatchId).toBe(batchId);
149	
150	    // confirmArrival (manual) propagates importBatchId to the session.
151	    const session = await reservationService.confirmArrival(reservation.id as number, 'manual', user);
152	    expect(session.importBatchId).toBe(batchId);
153	
154	    // completeSession transitions to Completed and calls generateOrder.
155	    await sessionService.completeSession(session.id as number, user);
156	
157	    // Order inherits importBatchId from the session — no manual patching.
158	    const order = await db.orders.where('sessionId').equals(session.id as number).first();
159	    expect(order).toBeTruthy();
160	    expect(order!.importBatchId).toBe(batchId);
161	    expect(order!.reconciliationStatus).toBe('Unreconciled');
162	
163	    // Reconciliation update does not break traceability.
164	    await orderService.setReconciliationStatus(order!.id as number, 'Matched', user);
165	    const reconciled = (await db.orders.get(order!.id as number))!;
166	    expect(reconciled.reconciliationStatus).toBe('Matched');
167	    expect(reconciled.importBatchId).toBe(batchId);
168	
169	    // Full chain: Order.importBatchId → ImportBatch with type='reservations'.
170	    const linkedBatch = (await db.importBatches.get(reconciled.importBatchId as number))!;
171	    expect(linkedBatch.id).toBe(batchId);
172	    expect(linkedBatch.type).toBe('reservations');
173	  });
174	
175	  it('Sessions import → completeSession → Order: sessions import provenance reaches billing', async () => {
176	    const { user, key } = await setupForImport();
177	
178	    // Seed a reservation in DB to reference from the session import.
179	    // Use reservationService so it goes through proper flow (no manual patching).
180	    const now = Date.now();
181	    const resStart = now + 2 * 60_000;
182	    const reservation = await reservationService.createReservation(
183	      {
184	        operationId: crypto.randomUUID(),
185	        bayId: (await db.bays.toCollection().first())!.id as number,
186	        siteId: user.siteId as number,
187	        userId: user.id as number,
188	        customerName: 'Session Import Driver',
189	        customerPlate: 'SIMP01',
190	        scheduledStart: resStart,
191	        scheduledEnd: resStart + 60 * 60_000
192	      },
193	      user,
194	      key
195	    );
196	
197	    // Import a session that references this reservation via the real sessions import flow.
198	    const sessionCsv = [
199	      'reservationId,startedAt',
200	      `${reservation.id as number},04/01/2026 09:00`
201	    ].join('\n');
202	    const sessionFile = new File([sessionCsv], 'sessions.csv', { type: 'text/csv' });
203	    const sessionFieldMap = importService.autoMapFields(['reservationId', 'startedAt'], 'sessions');
204	
205	    // Sessions import does not require an encryption key.
206	    const sessionBatch = await importService.startImport(sessionFile, 'sessions', sessionFieldMap, user);
207	    const sessionBatchId = sessionBatch.id as number;
208	    expect(sessionBatch.status).toBe('Complete');
209	
210	    // The imported session carries importBatchId from the sessions import batch.
211	    const importedSession = await db.sessions_charging
212	      .where('reservationId')
213	      .equals(reservation.id as number)
214	      .first();
215	    expect(importedSession).toBeTruthy();
