217	
218	    // completeSession transitions to Completed and calls generateOrder.
219	    await sessionService.completeSession(importedSession!.id as number, user);
220	
221	    // Order inherits importBatchId from the imported session.
222	    const order = await db.orders.where('sessionId').equals(importedSession!.id as number).first();
223	    expect(order).toBeTruthy();
224	    expect(order!.importBatchId).toBe(sessionBatchId);
225	    expect(order!.reconciliationStatus).toBe('Unreconciled');
226	
227	    // Reconciliation does not erase traceability.
228	    await orderService.setReconciliationStatus(order!.id as number, 'Matched', user);
229	    const reconciled = (await db.orders.get(order!.id as number))!;
230	    expect(reconciled.reconciliationStatus).toBe('Matched');
231	    expect(reconciled.importBatchId).toBe(sessionBatchId);
232	
233	    // Full chain: Order.importBatchId → ImportBatch with type='sessions'.
234	    const linkedBatch = (await db.importBatches.get(reconciled.importBatchId as number))!;
235	    expect(linkedBatch.id).toBe(sessionBatchId);
236	    expect(linkedBatch.type).toBe('sessions');
237	  });
