49	async function login(
50	  username: string,
51	  password: string
52	): Promise<{ user: User; encryptionKey: CryptoKey }> {
53	  const user = await db.users.where('username').equals(username).first();
54	  if (!user) {
55	    throw new AuthWrongPasswordError();
56	  }
57	
58	  const now = Date.now();
59	  if (user.lockedUntil && user.lockedUntil > now) {
60	    throw new AuthLockedError(user.lockedUntil - now);
61	  }
62	
63	  const isValid = await cryptoService.verifyPassword(password, user.passwordHash, user.salt);
64	  if (!isValid) {
65	    const nextAttempts = user.failedAttempts + 1;
66	    if (nextAttempts >= LOCKOUT_THRESHOLD) {
67	      const lockedUntil = now + LOCKOUT_DURATION_MS;
68	      await db.users.update(user.id as number, { failedAttempts: 0, lockedUntil });
69	      await auditService.log(user, 'AUTH_ACCOUNT_LOCKED', 'User', user.id as number, {
70	        lockedUntil
71	      });
72	      throw new AuthLockedError(LOCKOUT_DURATION_MS);
73	    }
74	
75	    await db.users.update(user.id as number, { failedAttempts: nextAttempts });
76	    await auditService.log(user, 'AUTH_FAILED_ATTEMPT', 'User', user.id as number, {
77	      failedAttempts: nextAttempts
78	    });
79	    throw new AuthWrongPasswordError();
80	  }
81	
82	  await db.users.update(user.id as number, { failedAttempts: 0, lockedUntil: undefined });
83	
84	  const sessionId = await db.sessions_auth.add({
85	    userId: user.id as number,
86	    createdAt: now,
87	    lastActiveAt: now
88	  });
89	
90	  storeSession({
91	    sessionId,
92	    userId: user.id as number,
93	    role: user.role,
94	    siteId: user.siteId
95	  });
96	
97	  const keySalt = user.salt;
98	  const encryptionKey = await cryptoService.deriveEncryptionKey(password, keySalt);
99	  await auditService.log(user, 'AUTH_LOGIN', 'User', user.id as number);
100	
101	  return {
102	    user: {
103	      ...user,
104	      failedAttempts: 0,
105	      lockedUntil: undefined
106	    },
107	    encryptionKey
108	  };
109	}
