115	async function restoreSession(): Promise<User | null> {
116	  const stored = getStoredSession();
117	  if (!stored) {
118	    return null;
119	  }
120	
121	  const session = await db.sessions_auth.get(stored.sessionId);
122	  if (!session) {
123	    localStorage.removeItem(AUTH_SESSION_KEY);
124	    return null;
125	  }
126	
127	  const now = Date.now();
128	  if (session.lastActiveAt < now - SESSION_DURATION_MS) {
129	    await db.sessions_auth.delete(session.id as number);
130	    localStorage.removeItem(AUTH_SESSION_KEY);
131	    return null;
132	  }
133	
134	  await db.sessions_auth.update(session.id as number, { lastActiveAt: now });
135	  const user = await db.users.get(stored.userId);
136	  if (!user) {
137	    localStorage.removeItem(AUTH_SESSION_KEY);
138	    return null;
139	  }
140	
141	  await auditService.log(user, 'AUTH_SESSION_RESTORED', 'SessionAuth', session.id as number);
142	
143	  return user;
144	}
